        .tab-switcher {
          display: flex;
          gap: 0.5rem;
          padding: 0.5rem;
          background: var(--surface);
          border: 1px solid var(--border);
          border-radius: 16px;
          margin-bottom: 2rem;
          max-width: 450px;
          box-shadow: var(--shadow-sm);
        }
        .tab-btn {
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 0.5rem;
          padding: 0.75rem 1.25rem;
