'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import {
  DashboardIcon,
  BookIcon,
  UsersIcon,
  ClockIcon,
  WalletIcon,
  CreditCardIcon,
  BarChartIcon,
  PhoneIcon,
  KeyIcon,
  TrendingUpIcon,
  MessageIcon,
  ShieldIcon,
  SparklesIcon,
  HomeIcon,
  MoonIcon,
  SunIcon,
  MenuIcon,
  XIcon,
  ChevronDownIcon,
} from './Icons';

interface SubItem {
  label: string;
  href: string;
}

interface NavItem {
  label: string;
  href?: string;
  icon: React.ReactNode;
  subItems?: SubItem[];
}

const navItems: NavItem[] = [
  { label: 'لوحة التحكم', href: '/admin', icon: <DashboardIcon /> },
  { label: 'الكورسات', href: '/admin/courses', icon: <BookIcon /> },
  { label: 'الطلاب', href: '/admin/students', icon: <UsersIcon /> },
  { label: 'الطلاب المعلقون', href: '/admin/pending-students', icon: <ClockIcon /> },
  { label: 'مراجعة الواجبات', href: '/admin/homework', icon: <BookIcon /> },
  { label: 'الشحن', href: '/admin/topups', icon: <WalletIcon /> },
  {
    label: 'الإحصائيات',
    icon: <BarChartIcon />,
    subItems: [
      { label: 'إحصائيات الكورسات', href: '/admin/stats/courses' },
      { label: 'السجل المالي للمنصة', href: '/admin/stats/finance' },
    ]
  },
  { label: 'أرقام الدفع', href: '/admin/payment-numbers', icon: <PhoneIcon /> },
  { label: 'أكواد المركز', href: '/admin/center-codes', icon: <KeyIcon /> },
  { label: 'قسم المتابعة', href: '/admin/monitoring', icon: <TrendingUpIcon /> },
  { label: 'المنتدى', href: '/admin/forum', icon: <MessageIcon /> },
  { label: 'الأمان', href: '/admin/security', icon: <ShieldIcon /> },
  { label: 'باقة المنصة', href: '/admin/plan', icon: <SparklesIcon /> },
];

export default function AdminSidebar() {
  const pathname = usePathname();
  const [theme, setTheme] = useState<'light' | 'dark'>('light');
  const [mounted, setMounted] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const [statsOpen, setStatsOpen] = useState(false);

  useEffect(() => {
    setMounted(true);
    const savedTheme = localStorage.getItem('theme') as 'light' | 'dark' | null;
    if (savedTheme) {
      setTheme(savedTheme);
    }
  }, []);

  useEffect(() => {
    if (pathname && pathname.startsWith('/admin/stats')) {
      setStatsOpen(true);
    }
  }, [pathname]);

  useEffect(() => {
    setMobileOpen(false);
  }, [pathname]);

  useEffect(() => {
    if (mobileOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = '';
    }
    return () => { document.body.style.overflow = ''; };
  }, [mobileOpen]);

  const toggleTheme = () => {
    const newTheme = theme === 'light' ? 'dark' : 'light';
    setTheme(newTheme);
    localStorage.setItem('theme', newTheme);
    document.documentElement.setAttribute('data-theme', newTheme);
  };

  const isActive = (href?: string) => {
    if (!href) return false;
    if (href === '/admin') {
      return pathname === '/admin';
    }
    return pathname === href || pathname.startsWith(`${href}/`);
  };

  const isStatsDropdownActive = () => {
    return pathname && pathname.startsWith('/admin/stats');
  };

  const sidebarContent = (
    <>
      <div className="admin-sidebar-logo">
        <span className="admin-logo-badge">
          م
        </span>
        <span>منصتنا</span>
        <button
          className="admin-sidebar-close"
          onClick={() => setMobileOpen(false)}
          aria-label="إغلاق"
        >
          <XIcon />
        </button>
      </div>

      <nav className="admin-nav">
        {navItems.map((item, index) => {
          if (item.subItems) {
            const active = isStatsDropdownActive();
            return (
              <div key={index}>
                <button
                  onClick={() => setStatsOpen(prev => !prev)}
                  className={`admin-nav-item w-full justify-between ${active ? 'active' : ''}`}
                >
                  <span className="flex items-center gap-2">
                    <span className="admin-nav-icon">{item.icon}</span>
                    <span>{item.label}</span>
                  </span>
                  <span
                    className="transition-transform duration-200"
                    style={{ transform: statsOpen ? 'rotate(180deg)' : 'none' }}
                  >
                    <ChevronDownIcon />
                  </span>
                </button>
                {statsOpen && (
                  <div className="admin-stats-submenu">
                    {item.subItems.map((sub, subIdx) => {
                      const subActive = pathname === sub.href;
                      return (
                        <Link
                          key={subIdx}
                          href={sub.href}
                          className={`admin-stats-subitem ${subActive ? 'active' : ''}`}
                        >
                          {sub.label}
                        </Link>
                      );
                    })}
                  </div>
                )}
              </div>
            );
          }

          return (
            <Link
              key={item.href}
              href={item.href || '#'}
              className={`admin-nav-item ${isActive(item.href) ? 'active' : ''}`}
            >
              <span className="admin-nav-icon">{item.icon}</span>
              <span>{item.label}</span>
            </Link>
          );
        })}
      </nav>

      <div className="mt-auto py-4 border-t">
        <Link href="/" className="admin-nav-item">
          <span className="admin-nav-icon"><HomeIcon /></span>
          <span>العودة للرئيسية</span>
        </Link>
        <button onClick={toggleTheme} className="admin-nav-item w-full">
          <span className="admin-nav-icon">
            {theme === 'light' ? <MoonIcon /> : <SunIcon />}
          </span>
          <span>{theme === 'light' ? 'الوضع المظلم' : 'الوضع الفاتح'}</span>
        </button>
      </div>
    </>
  );

  if (!mounted) {
    return (
      <aside className="admin-sidebar">
        {sidebarContent}
      </aside>
    );
  }

  return (
    <>
      <button
        className="admin-mobile-toggle"
        onClick={() => setMobileOpen(true)}
        aria-label="فتح القائمة"
      >
        <MenuIcon />
      </button>

      {mobileOpen && (
        <div
          className="admin-sidebar-backdrop"
          onClick={() => setMobileOpen(false)}
        />
      )}

      <aside className={`admin-sidebar ${mobileOpen ? 'mobile-open' : ''}`}>
        {sidebarContent}
      </aside>
    </>
  );
}

import { ReactNode } from 'react';

interface CardProps {
  children: ReactNode;
  className?: string;
  hover?: boolean;
  onClick?: () => void;
}

interface CardHeaderProps {
  children: ReactNode;
  className?: string;
}

interface CardTitleProps {
  children: ReactNode;
  className?: string;
}

interface CardContentProps {
  children: ReactNode;
  className?: string;
}

export function Card({ children, className = '', hover = true, onClick }: CardProps) {
  return (
    <div
      className={`card ${className}`}
      style={{ cursor: onClick ? 'pointer' : 'default' }}
      onClick={onClick}
    >
      {children}
    </div>
  );
}

export function CardHeader({ children, className = '' }: CardHeaderProps) {
  return (
    <div className={`card-header ${className}`}>
      {children}
    </div>
  );
}

export function CardTitle({ children, className = '' }: CardTitleProps) {
  return (
    <h3 className={`card-title ${className}`}>
      {children}
    </h3>
  );
}

export function CardContent({ children, className = '' }: CardContentProps) {
  return (
    <div className={className}>
      {children}
    </div>
  );
}

export default Card;

import { SVGProps, ReactNode } from 'react';

type IconProps = SVGProps<SVGSVGElement> & { size?: number };

const createIcon = (path: ReactNode, viewBox = '0 0 24 24') => {
  return ({ size = 20, ...props }: IconProps) => (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      width={size}
      height={size}
      viewBox={viewBox}
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
      {...props}
    >
      {path}
    </svg>
  );
};

// Navigation
export const HomeIcon = createIcon(<><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z" /><polyline points="9 22 9 12 15 12 15 22" /></>);
export const BookIcon = createIcon(<><path d="M2 3h6a4 4 0 0 1 4 4v14a3 3 0 0 0-3-3H2z" /><path d="M22 3h-6a4 4 0 0 0-4 4v14a3 3 0 0 1 3-3h7z" /></>);
export const WalletIcon = createIcon(<><path d="M21 12V7H5a2 2 0 0 1 0-4h14v4" /><path d="M3 5v14a2 2 0 0 0 2 2h16v-5" /><path d="M18 12a2 2 0 0 0 0 4h4v-4z" /></>);
export const UserIcon = createIcon(<><path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2" /><circle cx="12" cy="7" r="4" /></>);
export const UsersIcon = createIcon(<><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2" /><circle cx="9" cy="7" r="4" /><path d="M22 21v-2a4 4 0 0 0-3-3.87" /><path d="M16 3.13a4 4 0 0 1 0 7.75" /></>);
export const DashboardIcon = createIcon(<><rect x="3" y="3" width="7" height="9" rx="1" /><rect x="14" y="3" width="7" height="5" rx="1" /><rect x="14" y="12" width="7" height="9" rx="1" /><rect x="3" y="16" width="7" height="5" rx="1" /></>);
export const SettingsIcon = createIcon(<><circle cx="12" cy="12" r="3" /><path d="M12 1v2M12 21v2M4.22 4.22l1.42 1.42M18.36 18.36l1.42 1.42M1 12h2M21 12h2M4.22 19.78l1.42-1.42M18.36 5.64l1.42-1.42" /></>);
export const LogoutIcon = createIcon(<><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4" /><polyline points="16 17 21 12 16 7" /><line x1="21" y1="12" x2="9" y2="12" /></>);

// Actions
export const PlayIcon = createIcon(<><polygon points="5 3 19 12 5 21 5 3" /></>);
export const LockIcon = createIcon(<><rect x="3" y="11" width="18" height="11" rx="2" ry="2" /><path d="M7 11V7a5 5 0 0 1 10 0v4" /></>);
export const UnlockIcon = createIcon(<><rect x="3" y="11" width="18" height="11" rx="2" ry="2" /><path d="M7 11V7a5 5 0 0 1 9.9-1" /></>);
export const CheckIcon = createIcon(<><polyline points="20 6 9 17 4 12" /></>);
export const XIcon = createIcon(<><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></>);
export const MenuIcon = createIcon(<><line x1="4" y1="12" x2="20" y2="12" /><line x1="4" y1="6" x2="20" y2="6" /><line x1="4" y1="18" x2="20" y2="18" /></>);
export const SearchIcon = createIcon(<><circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" /></>);
export const FilterIcon = createIcon(<><polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3" /></>);
export const ArrowLeftIcon = createIcon(<><line x1="19" y1="12" x2="5" y2="12" /><polyline points="12 19 5 12 12 5" /></>);
export const ArrowRightIcon = createIcon(<><line x1="5" y1="12" x2="19" y2="12" /><polyline points="12 5 19 12 12 19" /></>);
