  AwardIcon, VideoIcon
} from '@/app/components/Icons';

interface Lecture {
  id: number;
  title: string;
  description: string;
  orderIndex: number;
  isLocked: boolean;
  videoStatus: string;
}

interface Exam {
  id: number;
  title: string;
  durationMinutes: number;
  passScore: number;
  startTime: string;
  endTime: string;
  isPurchased: boolean;
}

interface Course {
  id: number;
