  }

  /* ════════════════════════════════════════
     SCHEDULE
     ════════════════════════════════════════ */
  function renderSchedule() {
    return (
      <div className="animate-fade-in">
        <div className="sec-head">
          <div className="sec-head-icon"><BarChartIcon size={17} /></div>
          <div>
            <h3 className="sec-head-title">كورساتي</h3>
            <p className="sec-head-sub">تابع تقدمك وابدأ حضور محاضراتك</p>
          </div>
        </div>

        {schedule.length === 0 ? (
          <div className="empty-s card">
            <div className="empty-icon"><BookIcon size={40} /></div>
            <h4>لم تشترك في أي كورس بعد</h4>
            <p>فعّل كود السنتر المطبوع أو اشترك في الكورسات المتاحة للبدء فوراً.</p>
          </div>
        ) : (
          <div className="sched-list">
            {schedule.map((item, idx) => (
              <div key={item.courseId} className="sched-card card" style={{ padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '1rem', position: 'relative' }}>
                <div className="flex items-center justify-between gap-4">
                  <div className="flex items-center gap-3">
                    <div className="sched-icon-box" style={{ width: '48px', height: '48px', borderRadius: '12px', background: 'var(--soft-bg)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--primary)' }}>
                      <BookIcon size={22} />
                    </div>
                    <div>
                      <h4 className="font-bold text-base" style={{ color: 'var(--text-primary)', margin: 0 }}>{item.courseTitle}</h4>
                      <p className="text-xs text-muted" style={{ margin: '0.25rem 0 0' }}>تم إنجاز {item.completedLectures} من أصل {item.totalLectures} محاضرة</p>
                    </div>
                  </div>

                  <div className="text-right">
                    <span className="font-bold text-lg" style={{ color: 'var(--primary)' }}>{item.progressPercent}%</span>
                  </div>
                </div>

                <div className="sched-progress-container" style={{ width: '100%' }}>
                  <div className="sched-bar-track" style={{ height: '8px', background: 'var(--border-light)', borderRadius: '999px', overflow: 'hidden' }}>
                    <div className="sched-bar-fill" style={{ width: `${item.progressPercent}%`, height: '100%', borderRadius: '999px', background: 'var(--gradient-accent)' }} />
                  </div>
                </div>

                <div className="flex justify-between items-center mt-2">
                  <span className="text-xs text-muted" style={{ display: 'flex', alignItems: 'center', gap: '0.25rem' }}>
                    <ClockIcon size={14} />
                    {item.progressPercent === 100 ? 'مكتمل بنسبة 100%' : 'قيد الدراسة'}
                  </span>

                  <Link href={`/courses/${item.courseId}`} className="btn btn-sm btn-primary" style={{ padding: '0.5rem 1.25rem', borderRadius: '10px', fontSize: '0.85rem' }}>
                    متابعة التعلم
                  </Link>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    );
  }

  /* ─── EXAM RESULTS ─── */
  function renderExamResults() {
    return (
      <div className="animate-fade-in">
        <div className="sec-head">
          <div className="sec-head-icon"><AwardIcon size={17} /></div>
          <div>
            <h3 className="sec-head-title">نتائج الاختبارات</h3>
            <p className="sec-head-sub">استعرض درجاتك وراجع أخطاءك في الامتحانات السابقة</p>
          </div>
        </div>

        {examAttempts.length === 0 ? (
          <div className="empty-s card">
            <div className="empty-icon"><AwardIcon size={40} /></div>
            <h4>لا توجد نتائج اختبارات بعد</h4>
            <p>عندما تنهي أي اختبار، ستظهر تفاصيل درجاتك وإجاباتك هنا.</p>
          </div>
        ) : (
          <div className="table-container" style={{ margin: 0, border: '1px solid var(--border)', borderRadius: '12px', overflow: 'hidden' }}>
            <div className="table-responsive">
              <table className="table" style={{ margin: 0, borderCollapse: 'collapse', width: '100%' }}>
                <thead>
                  <tr style={{ background: 'var(--soft-bg)', borderBottom: '1px solid var(--border)' }}>
                    <th style={{ padding: '1rem 1.25rem', textAlign: 'right', fontWeight: 'bold' }}>الكورس</th>
                    <th style={{ padding: '1rem 1.25rem', textAlign: 'right', fontWeight: 'bold' }}>المحاضرة</th>
                    <th style={{ padding: '1rem 1.25rem', textAlign: 'center', fontWeight: 'bold' }}>النموذج</th>
                    <th style={{ padding: '1rem 1.25rem', textAlign: 'center', fontWeight: 'bold' }}>الدرجة</th>
                    <th style={{ padding: '1rem 1.25rem', textAlign: 'center', fontWeight: 'bold' }}>الحالة</th>
                    <th style={{ padding: '1rem 1.25rem', textAlign: 'center', fontWeight: 'bold' }}>تاريخ المحاولة</th>
                    <th style={{ padding: '1rem 1.25rem', textAlign: 'center', fontWeight: 'bold' }}>العمليات</th>
                  </tr>
                </thead>
                <tbody>
                  {examAttempts.map((attempt) => (
                    <tr key={attempt.id} style={{ borderBottom: '1px solid var(--border-light)' }}>
                      <td className="text-sm font-semibold" style={{ padding: '1rem 1.25rem', color: 'var(--text-primary)' }}>{attempt.courseTitle}</td>
                      <td className="text-sm font-semibold" style={{ padding: '1rem 1.25rem', color: 'var(--text-primary)' }}>{attempt.lectureTitle}</td>
                      <td className="text-sm text-center" style={{ padding: '1rem 1.25rem', color: 'var(--text-secondary)' }}>#{attempt.formIndex}</td>
                      <td className="text-sm font-bold text-center" style={{ padding: '1rem 1.25rem', color: 'var(--primary)' }}>{attempt.score}%</td>
                      <td className="text-sm text-center" style={{ padding: '1rem 1.25rem' }}>
                        <span style={{
                          display: 'inline-flex',
                          alignItems: 'center',
                          gap: '0.35rem',
                          padding: '0.25rem 0.75rem',
                          borderRadius: '99px',
                          fontSize: '0.75rem',
                          fontWeight: 'bold',
                          backgroundColor: attempt.passed ? 'rgba(16,185,129,0.1)' : 'rgba(239,68,68,0.1)',
                          color: attempt.passed ? '#10B981' : '#EF4444',
                          border: attempt.passed ? '1px solid rgba(16,185,129,0.2)' : '1px solid rgba(239,68,68,0.2)'
                        }}>
                          {attempt.passed ? 'ناجح' : 'راسب'}
                        </span>
                      </td>
                      <td className="text-sm text-center" style={{ padding: '1rem 1.25rem', color: 'var(--text-muted)' }}>
                        {new Date(attempt.completedAt).toLocaleDateString('ar-EG', { month: 'short', day: 'numeric', hour: 'numeric', minute: 'numeric' })}
                      </td>
                      <td className="text-sm text-center" style={{ padding: '1rem 1.25rem' }}>
                        <Link href={`/exams/${attempt.lectureId}?review=true&attempt_id=${attempt.id}`} className="btn btn-sm btn-outline">
                          مراجعة
                        </Link>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </div>
    );
  }

  /* ════════════════════════════════════════
     CENTER CODE
     ════════════════════════════════════════ */
  function renderCenterCode() {
    return (
      <div className="code-wrap animate-fade-in" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '60vh', width: '100%' }}>
        <div className="code-box card" style={{ padding: '2.5rem 2rem', border: '1px solid var(--border)', borderRadius: '24px', display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
          <div className="code-badge" style={{ marginBottom: '1.5rem', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <KeyIcon size={28} />
          </div>
          <h3 className="code-title" style={{ fontSize: '1.25rem', fontWeight: 800, textAlign: 'center', margin: '0 0 0.5rem' }}>تفعيل كود السنتر</h3>
          <p className="code-desc" style={{ textAlign: 'center', margin: '0 0 1.5rem' }}>أدخل كود التفعيل المطبوع المكون من 12 رقماً لفتح كورس أو محاضرة جديدة.</p>
          <form onSubmit={handleRedeemCode} className="code-form" style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '1.25rem', width: '100%' }}>
            <div className="code-inp-wrap" style={{ width: '100%', maxWidth: '340px', position: 'relative' }}>
              <input
                type="text"
                value={redeemCode}
                onChange={(e) => setRedeemCode(e.target.value.toUpperCase())}
                placeholder="XXXX-XXXX-XXXX"
                className="code-inp"
                required dir="ltr" maxLength={14}
                style={{
                  width: '100%',
                  border: '2px solid var(--border)',
                  borderRadius: '14px',
                  padding: '0.85rem 1rem',
                  fontSize: '1.4rem',
                  fontFamily: 'Courier New, monospace',
                  textAlign: 'center',
                  letterSpacing: '0.1em',
                  fontWeight: 'bold',
                  background: 'var(--soft-bg)',
                  outline: 'none',
                  transition: 'all 0.3s ease'
                }}
              />
              {codeSuccess && <span className="code-ok" style={{ left: '1.25rem' }}><CheckIcon size={20} /></span>}
            </div>
            <button
              type="submit"
              disabled={processing || !redeemCode.trim()}
              style={{
                width: '100%',
                maxWidth: '220px',
                padding: '0.75rem 1.5rem',
                borderRadius: '12px',
                fontSize: '0.95rem',
                fontWeight: 'bold',
                color: '#fff',
                background: codeSuccess 
                  ? 'linear-gradient(135deg, #10B981, #059669)' 
                  : 'linear-gradient(135deg, var(--primary), var(--secondary))',
                border: 'none',
                cursor: processing || !redeemCode.trim() ? 'not-allowed' : 'pointer',
                boxShadow: codeSuccess 
                  ? '0 4px 12px rgba(16,185,129,0.25)' 
                  : '0 4px 12px rgba(11,79,108,0.2)',
                transition: 'all 0.3s ease',
                opacity: processing || !redeemCode.trim() ? 0.6 : 1,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: '0.5rem'
              }}
            >
              {processing ? (
                <>
                  <span style={{
                    width: '14px',
                    height: '14px',
                    border: '2px solid rgba(255,255,255,0.2)',
                    borderTopColor: '#fff',
                    borderRadius: '50%',
                    animation: 'spin 0.7s linear infinite',
                    display: 'inline-block'
                  }} />
                  جاري التحقق...
                </>
              ) : codeSuccess ? (
                <>
                  <CheckIcon size={14} />
                  تم التفعيل!
                </>
              ) : (
                'تفعيل الكود'
              )}
            </button>
          </form>
          <p className="code-foot" style={{ marginTop: '1.25rem' }}>مثال للكود المقبول: 1234-5678-9012</p>
        </div>
      </div>
    );
  }

  /* ════════════════════════════════════════
     NOTIFICATIONS
     ════════════════════════════════════════ */
  function renderNotifications() {
    return (
      <div className="animate-fade-in">
        <div className="sec-head">
          <div className="sec-head-icon"><BellIcon size={17} /></div>
          <div>
            <h3 className="sec-head-title">الإشعارات</h3>
            <p className="sec-head-sub">آخر التحديثات والتنبيهات المستلمة</p>
          </div>
          {unreadCount > 0 && <span className="notif-pill">{unreadCount}</span>}
        </div>

        {notifications.length === 0 ? (
          <div className="empty-s card">
            <div className="empty-icon"><BellIcon size={40} /></div>
            <h4>صندوق الوارد فارغ</h4>
            <p>لا توجد إشعارات جديدة أو تنبيهات في الوقت الحالي.</p>
          </div>
        ) : (
          <div className="card" style={{ padding: 0, overflow: 'hidden', border: '1px solid var(--border)' }}>
            <div className="notif-list-container" style={{ display: 'flex', flexDirection: 'column' }}>
              {notifications.map((n, idx) => (
                <div 
                  key={n.id} 
                  className={`notif-item ${n.read ? 'notif-read-state' : 'notif-unread-state'}`}
                  style={{
                    padding: '1.25rem 1.5rem',
                    borderBottom: idx === notifications.length - 1 ? 'none' : '1px solid var(--border)',
                    display: 'flex',
                    gap: '1.25rem',
                    transition: 'all 0.25s ease',
                    position: 'relative'
                  }}
                >
                  {/* Indicator Dot */}
                  <div style={{ display: 'flex', alignItems: 'flex-start', paddingTop: '0.3rem' }}>
                    <div style={{
                      width: '10px',
                      height: '10px',
                      borderRadius: '50%',
                      backgroundColor: n.read ? 'var(--text-muted)' : 'var(--accent)',
                      boxShadow: n.read ? 'none' : '0 0 8px var(--accent)',
                      flexShrink: 0
                    }} />
                  </div>

                  {/* Notification Content */}
                  <div style={{ flex: 1 }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '0.4rem', gap: '1rem' }}>
                      <h4 style={{ margin: 0, fontSize: '0.95rem', fontWeight: 700, color: 'var(--text-primary)' }}>{n.title}</h4>
                      <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)', whiteSpace: 'nowrap' }}>{formatDate(n.createdAt)}</span>
                    </div>
                    <p style={{ margin: 0, fontSize: '0.85rem', color: 'var(--text-secondary)', lineHeight: '1.65' }}>{n.message}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    );
  }
}

'use client';

import { useEffect, useState, useCallback } from 'react';
import { useParams, useRouter } from 'next/navigation';
import Navbar from '@/app/components/Navbar';
import { useAuthGuard } from '../../hooks/useAuthGuard'; // 🚀 الدرع المركزي
import api from '@/lib/axios'; // 🚀 العميل الشبكي المحمي
import {
  ShieldIcon, ClockIcon, AwardIcon, CalendarIcon, CheckCircleIcon,
  CreditCardIcon, AlertTriangleIcon, FileTextIcon, PlayIcon
} from '@/app/components/Icons';

interface ExamDetails {
  id: number;
  title: string;
  courseTitle: string;
  instructions: string;
  pricePoints: number;
  durationMinutes: number;
  passScore: number;
  startTime: string;
  endTime: string;
  maxAttempts: number;
  questionsCount: number;
  isPurchased: boolean;
  attemptsUsed: number;
  status: 'upcoming' | 'active' | 'ended';
  userWalletBalance: number;
}

export default function StudentExamDetailsPage() {
  const router = useRouter();
  const params = useParams();
  const examId = params.id;

  const { isChecking } = useAuthGuard();

  const [exam, setExam] = useState<ExamDetails | null>(null);
  const [loading, setLoading] = useState(true);
  const [processingAction, setProcessingAction] = useState(false);

  const [toast, setToast] = useState<{ visible: boolean; message: string; type: 'success' | 'error' }>({ visible: false, message: '', type: 'success' });
  const [confirmDialog, setConfirmDialog] = useState<{ visible: boolean; message: string; onConfirm: () => void } | null>(null);

  const showToast = useCallback((message: string, type: 'success' | 'error') => {
    setToast({ visible: true, message, type });
    setTimeout(() => setToast({ visible: false, message: '', type: 'success' }), 4000);
  }, []);

  // تجميد التمرير للـ Modal
  useEffect(() => {
    if (confirmDialog) document.body.style.overflow = 'hidden';
    else document.body.style.overflow = '';
    return () => { document.body.style.overflow = ''; };
  }, [confirmDialog]);

  useEffect(() => {
    if (!isChecking && examId) {
      fetchExamDetails();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [examId, isChecking]);

  const fetchExamDetails = async () => {
    setLoading(true);
    try {
      // جلب التفاصيل مع حالة الشراء والرصيد الحالي للطالب
      const response = await api.get(`/comprehensive-exams/${examId}`);
      const data = response.data?.data || response.data;
      
      setExam({
        id: data.id,
        title: data.title,
        courseTitle: data.course_title ?? data.courseTitle ?? 'عام',
        instructions: data.instructions,
        pricePoints: data.price_points ?? data.pricePoints ?? 0,
        durationMinutes: data.duration_minutes ?? data.durationMinutes ?? 60,
        passScore: data.pass_score ?? data.passScore ?? 50,
        startTime: data.start_time ?? data.startTime,
        endTime: data.end_time ?? data.endTime,
        maxAttempts: data.max_attempts ?? data.maxAttempts ?? 1,
        questionsCount: data.questions_count ?? data.questionsCount ?? 0,
        isPurchased: !!(data.is_purchased ?? data.isPurchased),
        attemptsUsed: data.attempts_used ?? data.attemptsUsed ?? 0,
        status: data.status ?? 'active',
        userWalletBalance: data.user_wallet_balance ?? data.userWalletBalance ?? 0,
      });
    } catch (err: any) {
      showToast(err?.message || 'فشل تحميل بيانات الاختبار', 'error');
      setTimeout(() => router.push('/courses'), 2000);
    } finally {
      setLoading(false);
    }
  };

  const handlePurchase = () => {
    if (!exam) return;
    
    if (exam.userWalletBalance < exam.pricePoints) {
      showToast('رصيد محفظتك غير كافٍ. قم بشحن المحفظة أولاً.', 'error');
      return;
    }

    setConfirmDialog({
      visible: true,
      message: `سيتم خصم ${exam.pricePoints} ج.م من رصيد محفظتك لشراء هذا الاختبار. هل أنت متأكد؟`,
      onConfirm: async () => {
        setConfirmDialog(null);
        setProcessingAction(true);
        try {
          await api.post(`/comprehensive-exams/${exam.id}/purchase`);
          showToast('تم شراء الاختبار بنجاح! يمكنك البدء الآن.', 'success');
          fetchExamDetails(); // تحديث الحالة لتظهر "بدء الاختبار"
        } catch (err: any) {
          showToast(err?.message || err?.error || 'فشل إتمام عملية الشراء', 'error');
        } finally {
          setProcessingAction(false);
        }
      }
    });
  };

  const handleStartExam = () => {
    if (!exam) return;

    if (exam.status === 'upcoming') {
      showToast('لم يحن موعد الاختبار بعد.', 'error');
      return;
    }
    if (exam.status === 'ended') {
      showToast('لقد انتهى الوقت المخصص لهذا الاختبار.', 'error');
      return;
    }
    if (exam.attemptsUsed >= exam.maxAttempts) {
      showToast('لقد استنفدت الحد الأقصى للمحاولات المسموحة لك.', 'error');
      return;
    }

    setConfirmDialog({
      visible: true,
      message: 'بمجرد الضغط على "تأكيد"، سيبدأ العداد التنازلي للاختبار ولن تتمكن من إيقافه. تأكد من استقرار الإنترنت لديك. هل أنت مستعد؟',
      onConfirm: () => {
        setConfirmDialog(null);
        // توجيه الطالب لصفحة قاعة الامتحان (حيث العداد والأسئلة)
        router.push(`/student/exams/${exam.id}/take`);
      }
    });
  };

  if (isChecking || loading) {
    return (
      <div className="min-h-screen bg-[#f8fafc] flex flex-col">
        <Navbar />
        <div className="flex-1 flex flex-col items-center justify-center">
          <div className="spinner spinner-primary spinner-lg mb-4" />
          <p className="font-bold text-gray-500">جاري تجهيز بيانات الاختبار...</p>
        </div>
      </div>
    );
  }

  if (!exam) return null;

  return (
    <div className="min-h-screen bg-[#f8fafc] flex flex-col pb-20">
      <Navbar />

      {/* 🚀 نظام التنبيهات */}
      <div className="toast-container" style={{ position: 'fixed', top: '2rem', left: '2rem', zIndex: 1000, transition: 'all 0.3s', opacity: toast.visible ? 1 : 0, pointerEvents: toast.visible ? 'auto' : 'none' }}>
        <div className={`toast-content ${toast.type === 'success' ? 'toast-success' : 'toast-error'}`}>
          {toast.type === 'success' ? <CheckCircleIcon size={20} /> : <AlertTriangleIcon size={20} />}
          {toast.message}
        </div>
      </div>

      {/* 🚀 نافذة التأكيد الذكية */}
      {confirmDialog && (
        <div className="fixed inset-0 flex items-center justify-center z-[100] p-4 animate-fade-in" style={{ backgroundColor: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(5px)' }} onClick={() => setConfirmDialog(null)}>
          <div className="bg-white shadow-2xl max-w-md w-full text-center p-8 rounded-3xl animate-scale-up" onClick={e => e.stopPropagation()}>
            <div className="flex justify-center mb-5 text-primary"><ShieldIcon size={56} /></div>
            <h3 className="text-2xl font-black text-gray-900 mb-4">تأكيد الإجراء</h3>
            <p className="text-gray-600 mb-8 leading-relaxed font-bold">{confirmDialog.message}</p>
            <div className="flex gap-4">
              <button onClick={() => setConfirmDialog(null)} className="btn btn-outline flex-1 py-3 font-bold border-gray-300">إلغاء</button>
              <button onClick={confirmDialog.onConfirm} className="btn btn-primary flex-1 py-3 font-black shadow-lg shadow-blue-200">تأكيد الإجراء</button>
            </div>
          </div>
        </div>
      )}

      <main className="flex-1 max-w-4xl w-full mx-auto px-4 sm:px-6 lg:px-8 pt-8 animate-fade-in">
        <button onClick={() => router.back()} className="text-sm font-bold text-gray-400 hover:text-primary mb-6 flex items-center gap-1 transition-colors">
          &rarr; العودة للمتجر
        </button>

        {/* كارت معلومات الاختبار */}
        <div className="bg-white rounded-3xl border border-gray-100 shadow-xl overflow-hidden mb-8 relative">
          {/* شريط زينة علوي */}
          <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-primary to-blue-400"></div>
          
          <div className="p-8 md:p-10">
            <span className="inline-block px-3 py-1.5 bg-blue-50 text-primary text-xs font-black rounded-lg border border-blue-100 mb-4">
              كورس: {exam.courseTitle}
            </span>
            <h1 className="text-3xl md:text-4xl font-black text-gray-900 leading-tight mb-8">{exam.title}</h1>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8 bg-gray-50 p-6 rounded-2xl border border-gray-100">
              <div>
                <span className="block text-xs font-bold text-gray-400 mb-1 flex items-center gap-1"><ClockIcon size={14}/> المدة</span>
                <span className="font-black text-gray-800 text-lg">{exam.durationMinutes} دقيقة</span>
              </div>
              <div className="border-r border-gray-200 pr-4">
                <span className="block text-xs font-bold text-gray-400 mb-1 flex items-center gap-1"><FileTextIcon size={14}/> الأسئلة</span>
                <span className="font-black text-primary text-lg">{exam.questionsCount} أسئلة</span>
              </div>
              <div className="border-r border-gray-200 pr-4">
                <span className="block text-xs font-bold text-gray-400 mb-1 flex items-center gap-1"><AwardIcon size={14}/> النجاح</span>
                <span className="font-black text-success text-lg">{exam.passScore}%</span>
              </div>
              <div className="border-r border-gray-200 pr-4">
                <span className="block text-xs font-bold text-gray-400 mb-1 flex items-center gap-1"><ShieldIcon size={14}/> المحاولات</span>
                <span className="font-black text-orange-600 text-lg">{exam.attemptsUsed} / {exam.maxAttempts}</span>
              </div>
            </div>

            <div className="bg-blue-50/50 p-6 rounded-2xl border border-blue-100 mb-8">
              <h4 className="font-black text-primary flex items-center gap-2 mb-4"><CalendarIcon size={20} /> نافذة الإتاحة (Time Window)</h4>
              <div className="flex flex-col md:flex-row justify-between gap-4 font-bold text-gray-700">
                <div className="flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-green-500"></span>
                  يبدأ: <span dir="ltr">{new Date(exam.startTime).toLocaleString('ar-EG')}</span>
                </div>
                <div className="flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-red-500"></span>
                  يغلق: <span dir="ltr">{new Date(exam.endTime).toLocaleString('ar-EG')}</span>
                </div>
              </div>
            </div>

            {exam.instructions && (
              <div className="mb-8">
                <h4 className="font-black text-gray-800 flex items-center gap-2 mb-3"><AlertTriangleIcon size={20} className="text-warning"/> تعليمات قبل البدء</h4>
                <p className="text-gray-600 font-medium leading-relaxed bg-gray-50 p-5 rounded-2xl border border-gray-100 whitespace-pre-wrap">
                  {exam.instructions}
                </p>
              </div>
            )}
            
            <div className="pt-8 border-t border-gray-100 flex flex-col items-center">
              {exam.isPurchased ? (
                <div className="w-full flex flex-col items-center">
                  {exam.status === 'upcoming' && (
                    <div className="w-full bg-yellow-50 text-yellow-800 p-4 rounded-xl border border-yellow-200 font-bold text-center mb-4">
                      ⏳ لم يحن موعد الاختبار بعد. يرجى الانتظار حتى الموعد المحدد.
                    </div>
                  )}
                  {exam.status === 'ended' && (
                    <div className="w-full bg-gray-100 text-gray-600 p-4 rounded-xl border border-gray-200 font-bold text-center mb-4">
                      🔒 عذراً، لقد انتهت النافذة الزمنية المخصصة لهذا الاختبار وتم إغلاقه.
                    </div>
                  )}
                  <button 
                    onClick={handleStartExam} 
                    disabled={exam.status !== 'active' || exam.attemptsUsed >= exam.maxAttempts}
                    className="w-full md:w-auto min-w-[300px] btn btn-primary py-4 text-lg font-black shadow-xl shadow-blue-200 flex justify-center items-center gap-3 transition-transform hover:-translate-y-1 disabled:opacity-50 disabled:hover:translate-y-0"
                  >
                    <PlayIcon size={24} /> {exam.attemptsUsed >= exam.maxAttempts ? 'استنفدت المحاولات المسموحة' : 'بدء الاختبار الآن'}
                  </button>
                </div>
              ) : (
                <div className="w-full flex flex-col items-center bg-gray-50 p-6 rounded-2xl border border-gray-200">
                  <span className="text-sm font-bold text-gray-500 mb-2">هذا الاختبار متاح للشراء كمنتج مستقل</span>
                  <div className="font-black text-4xl text-primary font-mono mb-6">
                    {exam.pricePoints > 0 ? `${exam.pricePoints} ج.م` : 'مجاني'}
                  </div>
                  
                  <div className="w-full flex flex-col sm:flex-row justify-center gap-4">
                    <div className="bg-white px-5 py-3 rounded-xl border border-gray-200 flex items-center justify-between min-w-[200px] shadow-sm">
                      <span className="text-xs font-bold text-gray-400 flex items-center gap-1.5"><CreditCardIcon size={16}/> رصيدك الحالي:</span>
                      <span className="font-black text-success" dir="ltr">{exam.userWalletBalance} ج</span>
                    </div>
                    <button 
                      onClick={handlePurchase}
                      disabled={processingAction}
                      className="btn btn-success py-3 px-8 text-base font-black shadow-lg shadow-green-200 flex justify-center items-center gap-2"
                    >
                      {processingAction ? <span className="spinner spinner-light w-5 h-5 border-2" /> : <><CheckCircleIcon size={20}/> إتمام الشراء وخصم الرصيد</>}
                    </button>
                  </div>
                </div>
              )}
            </div>

          </div>
        </div>
      </main>

      <style jsx global>{`
        .animate-fade-in { animation: fadeIn 0.4s ease-out forwards; }
        .animate-scale-up { animation: scaleUp 0.3s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes scaleUp { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
      `}</style>
    </div>
  );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import Navbar from '@/app/components/Navbar';
import { useRouter } from 'next/navigation';
import {
  MessageIcon,
  UserIcon,
  GraduationCapIcon,
  TrashIcon,
  ImageIcon,
  UploadIcon,
  FileTextIcon,
  ClockIcon,
  ChevronDownIcon,
  CheckCircleIcon,
  AlertCircleIcon,
} from '@/app/components/Icons';

const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";

interface ForumPost {
  id: number;
  body: string;
  image: string | null;
  authorName?: string;
  isOwn?: boolean;
  adminReply: string | null;
  adminReplyAudio?: string | null;
  adminReplyImage?: string | null;
  repliedAt: string | null;
  createdAt: string;
}

export default function StudentForumPage() {
  const router = useRouter();
  const [posts, setPosts] = useState<ForumPost[]>([]);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [academicYear, setAcademicYear] = useState('');

  const [newBody, setNewBody] = useState('');
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [currentPage, setCurrentPage] = useState(1);
  const [lastPage, setLastPage] = useState(1);

  const [toast, setToast] = useState<{ visible: boolean; message: string; type: 'success' | 'error' }>({ visible: false, message: '', type: 'success' });
  const [confirmDialog, setConfirmDialog] = useState<{ visible: boolean; postId: number } | null>(null);

  const showToast = (message: string, type: 'success' | 'error') => {
    setToast({ visible: true, message, type });
    setTimeout(() => setToast({ visible: false, message: '', type: 'success' }), 4000);
  };

  const getToken = () => {
    return document.cookie.split('; ').find(row => row.startsWith('token='))?.split('=')[1] || localStorage.getItem('token');
  };

  const fetchPosts = async (page = 1, append = false) => {
    try {
      const token = getToken();
      if (!token) return router.push('/login');

      const statusRes = await fetch(`${API_URL}/api/auth/status`, {
        headers: { Authorization: `Bearer ${token}`, Accept: 'application/json' },
      });
      if (statusRes.ok) {
        const statusData = await statusRes.json();
        if (statusData.data?.status === 'pending') {
          router.replace('/waiting-room');
          return;
        }
      }

      const res = await fetch(`${API_URL}/api/forum?page=${page}`, {
        headers: { 'Authorization': `Bearer ${token}`, 'Accept': 'application/json' },
      });

      if (res.ok) {
        const data = await res.json();
        const fetchedPosts = data.data.posts;

        if (append) {
          setPosts(prev => [...prev, ...fetchedPosts]);
        } else {
          setPosts(fetchedPosts);
        }

        if (data.data.academicYear) {
          setAcademicYear(data.data.academicYear);
        }

        setCurrentPage(data.data.pagination.currentPage);
        setLastPage(data.data.pagination.lastPage);
      }
    } catch (err) {
      showToast('خطأ في جلب البيانات', 'error');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchPosts(1);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (file.size > 5 * 1024 * 1024) {
      showToast('حجم الصورة يجب أن يكون أقل من 5 ميجابايت', 'error');
      if (fileInputRef.current) fileInputRef.current.value = '';
      return;
    }

    const allowedTypes = ['image/jpeg', 'image/png', 'image/webp', 'image/jpg'];
    if (!allowedTypes.includes(file.type)) {
      showToast('الصيغ المسموحة هي JPG, PNG, WEBP فقط', 'error');
      if (fileInputRef.current) fileInputRef.current.value = '';
      return;
    }

    setImageFile(file);
    setImagePreview(URL.createObjectURL(file));
  };

  const removeImage = () => {
    setImageFile(null);
    setImagePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newBody.trim().length < 5) {
      showToast('نص السؤال يجب أن يكون 5 أحرف على الأقل', 'error');
      return;
    }

    setSubmitting(true);
    try {
      const token = getToken();

      const formData = new FormData();
      formData.append('body', newBody);
      if (imageFile) {
        formData.append('image', imageFile);
      }

      const res = await fetch(`${API_URL}/api/forum`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Accept': 'application/json'
        },
        body: formData,
      });

      if (res.ok) {
        showToast('تم إرسال استفسارك بنجاح!', 'success');
        setNewBody('');
        removeImage();
        fetchPosts(1, false);
      } else {
        const errorData = await res.json();
        showToast(errorData.message || 'فشل إرسال السؤال', 'error');
      }
    } catch (err) {
      showToast('خطأ في الاتصال بالخادم', 'error');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async () => {
    if (!confirmDialog) return;
    try {
      const token = getToken();
      const res = await fetch(`${API_URL}/api/forum/${confirmDialog.postId}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}`, 'Accept': 'application/json' },
      });

      if (res.ok) {
        showToast('تم حذف السؤال بنجاح', 'success');
        setPosts(prev => prev.filter(p => p.id !== confirmDialog.postId));
      } else {
        showToast('فشل حذف السؤال', 'error');
      }
    } catch (err) {
      showToast('خطأ في الاتصال بالخادم', 'error');
    } finally {
      setConfirmDialog(null);
    }
  };

  const getImageUrl = (path: string) => {
    if (path.startsWith('http')) return path;
    return `${API_URL}/storage/${path}`;
  };

  const formatDate = (isoString: string) => {
    const date = new Date(isoString);
    return new Intl.DateTimeFormat('ar-EG', { dateStyle: 'medium', timeStyle: 'short' }).format(date);
  };

  return (
    <div className="page-container">
      <Navbar />

      <div className={`toast-container ${toast.visible ? 'show' : ''}`}>
        <div className={`toast-content ${toast.type}`}>
          <span className="toast-icon">{toast.type === 'success' ? <CheckCircleIcon size={20} /> : <AlertCircleIcon size={20} />}</span>
          {toast.message}
        </div>
      </div>

      {confirmDialog && (
        <div className="animate-fade-in" style={{ position: 'fixed', inset: 0, backgroundColor: 'rgba(0,0,0,0.8)', backdropFilter: 'blur(4px)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <div className="card" style={{ maxWidth: '400px', width: '90%', textAlign: 'center' }}>
            <div className="empty-state-icon" style={{ margin: '0 auto 1rem' }}>
              <TrashIcon size={32} />
            </div>
            <h3 style={{ color: 'var(--error)', marginBottom: '1rem' }}>تأكيد الحذف</h3>
            <p className="text-muted" style={{ marginBottom: '2rem', lineHeight: '1.6' }}>هل أنت متأكد من حذف هذا السؤال؟ سيتم إخفاؤه تماماً.</p>
            <div className="flex gap-4 justify-center">
              <button onClick={() => setConfirmDialog(null)} className="btn btn-outline" style={{ flex: 1 }}>إلغاء</button>
              <button onClick={handleDelete} className="btn btn-danger" style={{ flex: 1 }}>نعم، احذف</button>
            </div>
          </div>
        </div>
      )}

      <main className="page-content animate-fade-in">

        <div className="page-header" style={{ justifyContent: 'center' }}>
          <div style={{ textAlign: 'center' }}>
            <h1 className="page-title flex items-center justify-center gap-3">
              <MessageIcon size={28} />
              منتدى {academicYear || 'المنتدى الأكاديمي'}
            </h1>
            <p className="page-subtitle">اسأل، شارك، وتفاعل مع طلاب {academicYear || 'صفك'} وفريق الدعم.</p>
          </div>
        </div>

        <div className="card mb-8" style={{ borderColor: 'var(--primary)' }}>
          <form onSubmit={handleSubmit}>
            <div className="form-group mb-4">
              <label className="form-label" style={{ fontWeight: 700, fontSize: '1.125rem' }}>اطرح سؤالك هنا:</label>
              <textarea
                value={newBody}
                onChange={(e) => setNewBody(e.target.value)}
                className="input-field"
                style={{ minHeight: '120px', padding: '1rem', fontSize: '1.125rem' }}
                rows={4}
                placeholder="اكتب استفسارك بوضوح، وسيتم الرد عليك في أقرب وقت..."
                required
              />
            </div>

            {imagePreview && (
              <div className="relative inline-block mb-4" style={{ border: '1px solid var(--border)', borderRadius: 'var(--radius-lg)', overflow: 'hidden', backgroundColor: 'var(--surface)', padding: '0.5rem' }}>
                {/* eslint-disable-next-line @next/next/no-img-element */}
                <img src={imagePreview} alt="Preview" style={{ maxHeight: '12rem', borderRadius: 'var(--radius-sm)', objectFit: 'contain' }} />
                <button
                  type="button"
                  onClick={removeImage}
                  className="btn btn-danger btn-sm"
                  style={{ position: 'absolute', top: '0.75rem', right: '0.75rem', minWidth: 'unset', width: '2rem', height: '2rem', borderRadius: '50%', padding: 0, display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                  title="حذف الصورة"
                >
                  <TrashIcon size={14} />
                </button>
              </div>
            )}

            <div className="flex flex-col sm:flex-row justify-between items-center gap-4" style={{ borderTop: '1px solid var(--border-light)', paddingTop: '1rem' }}>
              <div className="w-full sm:w-auto">
                <input
                  type="file"
                  accept="image/jpeg,image/png,image/webp,image/jpg"
                  className="hidden"
                  ref={fileInputRef}
                  onChange={handleImageChange}
                />
                <button
                  type="button"
                  onClick={() => fileInputRef.current?.click()}
                  className="btn btn-outline w-full sm:w-auto flex items-center justify-center gap-2"
                >
                  <ImageIcon size={18} />
                  {imageFile ? 'تغيير الصورة' : 'إرفاق صورة'}
                </button>
              </div>

              <button
                type="submit"
                disabled={submitting || newBody.trim().length < 5}
                className="btn btn-primary w-full sm:w-auto"
                style={{ paddingInline: '2rem' }}
              >
                {submitting ? (
                  <>
                    <span className="spinner spinner-white" style={{ width: 16, height: 16, borderWidth: 2 }}></span>
                    جاري الإرسال...
                  </>
                ) : (
                  <>
                    <UploadIcon size={18} />
                    إرسال السؤال
                  </>
                )}
              </button>
            </div>
          </form>
        </div>

        {loading && posts.length === 0 ? (
          <div className="loading-state">
            <div className="spinner spinner-lg"></div>
            <p style={{ marginTop: '1rem' }}>جاري تحميل الأسئلة...</p>
          </div>
        ) : posts.length === 0 ? (
          <div className="empty-state">
            <div className="empty-state-icon">
              <FileTextIcon size={32} />
            </div>
            <h3>لا توجد أسئلة سابقة</h3>
            <p>كن أول من يطرح سؤالاً في المنتدى!</p>
          </div>
        ) : (
          <div className="space-y-6">
            <h3 className="flex items-center gap-2 font-bold" style={{ color: 'var(--text-muted)', borderBottom: '1px solid var(--border)', paddingBottom: '0.5rem' }}>
              <MessageIcon size={20} />
              سجّل استفساراتك
            </h3>

            {posts.map(post => (
              <div key={post.id} className="card" style={{ padding: 0, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>

                <div className="p-6" style={{ backgroundColor: 'rgba(0,0,0,0.03)' }}>
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex items-center gap-3">
                      <div className="student-avatar" style={{ width: '2.5rem', height: '2.5rem', minWidth: '2.5rem', fontSize: '0.875rem' }}>
                        {(post.authorName || '?').charAt(0)}
                      </div>
                      <div>
                        <span className="font-bold" style={{ color: 'var(--text-primary)', display: 'block' }}>
                          {post.isOwn ? 'أنت' : (post.authorName || 'طالب')}
                        </span>
                        <span className="text-muted" style={{ fontSize: '0.75rem' }} dir="ltr">{formatDate(post.createdAt)}</span>
                      </div>
                    </div>
                    {post.isOwn && (
                      <button onClick={() => setConfirmDialog({ visible: true, postId: post.id })} className="btn btn-ghost btn-sm" style={{ color: 'var(--text-muted)' }}>
                        <TrashIcon size={16} />
                      </button>
                    )}
                  </div>

                  <p className="text-secondary" style={{ lineHeight: '1.8', whiteSpace: 'pre-wrap', fontSize: '1.125rem', color: 'var(--text-primary)' }}>{post.body}</p>

                  {post.image && (
                    <div className="mt-4" style={{ borderRadius: 'var(--radius-md)', overflow: 'hidden', border: '1px solid var(--border)', display: 'inline-block' }}>
                      {/* eslint-disable-next-line @next/next/no-img-element */}
                      <img src={getImageUrl(post.image)} alt="مرفق الطالب" style={{ maxHeight: '16rem', objectFit: 'contain' }} />
                    </div>
                  )}
                </div>

                {(post.adminReply || post.adminReplyAudio || post.adminReplyImage) ? (
                  <div style={{ padding: '1.5rem', backgroundColor: 'rgba(11, 79, 108, 0.04)', borderTop: '1px solid rgba(11, 79, 108, 0.15)', position: 'relative' }}>
                    <div style={{ position: 'absolute', right: 0, top: 0, bottom: 0, width: '4px', background: 'var(--gradient-primary)' }}></div>

                    <div className="flex items-center gap-3 mb-3">
                      <div className="flex items-center justify-center" style={{ width: '2.5rem', height: '2.5rem', borderRadius: '50%', background: 'var(--gradient-primary)', color: 'white', boxShadow: 'var(--shadow-md)' }}>
                        <GraduationCapIcon size={20} />
                      </div>
                      <div>
                        <span className="font-bold" style={{ color: 'var(--primary)', display: 'block' }}>فريق الدعم (الإدارة)</span>
                        {post.repliedAt && <span className="text-muted" style={{ fontSize: '0.75rem' }} dir="ltr">{formatDate(post.repliedAt)}</span>}
                      </div>
                    </div>

                    <div style={{ marginRight: '3rem' }}>
                      {post.adminReply && (
                        <p className="card-content" style={{ padding: '0.75rem', backgroundColor: 'rgba(0,0,0,0.03)', borderRadius: 'var(--radius-sm)', whiteSpace: 'pre-wrap', fontWeight: 500 }}>
                          {post.adminReply}
                        </p>
                      )}
                      {post.adminReplyAudio && (
                        <div className="mt-3">
                          <audio controls src={getImageUrl(post.adminReplyAudio)} className="w-full" style={{ maxWidth: '28rem', height: '2.5rem' }} />
                        </div>
                      )}
                      {post.adminReplyImage && (
                        <div className="mt-3" style={{ borderRadius: 'var(--radius-sm)', overflow: 'hidden', border: '1px solid var(--border)', display: 'inline-block' }}>
                          {/* eslint-disable-next-line @next/next/no-img-element */}
                          <img src={getImageUrl(post.adminReplyImage)} alt="مرفق الإدارة" style={{ maxHeight: '16rem', objectFit: 'contain' }} />
                        </div>
                      )}
                    </div>
                  </div>
                ) : (
                  <div className="banner banner-warning" style={{ borderRadius: 0, margin: 0 }}>
                    <ClockIcon size={16} />
                    قيد الانتظار... سيتم الرد عليك قريباً.
                  </div>
                )}

              </div>
            ))}

            {currentPage < lastPage && (
              <div className="text-center pt-4">
                <button
                  onClick={() => fetchPosts(currentPage + 1, true)}
                  className="btn btn-outline"
                  style={{ borderRadius: 'var(--radius-full)', paddingInline: '2rem' }}
                  disabled={loading}
                >
                  {loading ? (
                    <>
                      <span className="spinner" style={{ width: 16, height: 16, borderWidth: 2 }}></span>
                      جاري التحميل...
                    </>
                  ) : (
                    <>
                      <ChevronDownIcon size={18} />
                      عرض الأسئلة الأقدم
                    </>
                  )}
                </button>
              </div>
            )}

          </div>
        )}

      </main>
    </div>
  );
}

// frontend/app/hooks/useAuthGuard.ts
'use client';

import { useEffect, useState } from 'react';
import { useRouter, usePathname } from 'next/navigation';
import { useAuthStore } from '@/store/useAuthStore';
import Cookies from 'js-cookie';

export function useAuthGuard(allowedRoles?: string[]) {
  const router = useRouter();
  const pathname = usePathname();

  // 1. استدعاء الذاكرة المركزية
  const { user, isAuthenticated, isLoading, fetchUser } = useAuthStore();

  // 2. حالة الترطيب: تمنع أي طرد متسرع حتى نتحقق من التوكن
  const [isHydrating, setIsHydrating] = useState(true);

  useEffect(() => {
    const initGuard = async () => {
      const token = Cookies.get('token') || localStorage.getItem('token');

      // إذا لا يوجد توكن إطلاقاً، أنهي الترطيب ليتم الطرد
      if (!token) {
        setIsHydrating(false);
        return;
      }

      // إذا كان هناك توكن، لكن الذاكرة فارغة (حدث ريفريش أو انتقال)
      if (!isAuthenticated) {
        try {
          await fetchUser(); // السحر هنا: نجبر النظام على جلب البيانات
        } catch (error) {
          Cookies.remove('token');
          localStorage.removeItem('token');
        }
      }

      // انتهت عملية التحقق بنجاح
      setIsHydrating(false);
    };

    initGuard();
  }, []); // تعمل مرة واحدة فقط عند فتح الصفحة

  // حماية ذكية لمنع مشكلة (Infinite Loop) إذا تم تمرير المصفوفة مباشرة
  const rolesString = allowedRoles ? allowedRoles.join(',') : '';

  // 3. درع التوجيه الصارم (لا يتدخل إلا بعد انتهاء الترطيب)
  useEffect(() => {
    if (isHydrating || isLoading) return;

    // إذا لم ينجح الدخول، اطرده لصفحة التسجيل
    if (!isAuthenticated) {
      router.replace(`/login?redirect=${pathname}`);
      return;
    }

    // التوجيه الإجباري حسب نوع الحساب (الفصل بين الإدارة والطلاب)
    if (user) {
      // منع الطالب من دخول الإدارة
      if (user.role !== 'admin' && pathname.startsWith('/admin')) {
        router.replace('/dashboard');
        return;
      }

      // توجيه الأدمن للإدارة فقط إذا حاول الدخول للوحة الطالب الخاصة (مثال: /dashboard)
      if (user.role === 'admin' && pathname.startsWith('/dashboard')) {
        router.replace('/admin');
        return;
      }

      // if (allowedRoles && !allowedRoles.includes(user.role)) {
      //   const redirectPath = user.role === 'admin' ? '/admin' : '/dashboard';
      //   router.replace(redirectPath);
      // }
    }
  }, [isHydrating, isLoading, isAuthenticated, user, pathname, rolesString, router]);

  return { isChecking: isHydrating || isLoading, user, isAuthenticated };
}

// app/lectures/[id]/page.tsx
'use client';

import { useEffect, useState, useRef } from 'react';
import { useRouter, useParams } from 'next/navigation';
import Navbar from '@/app/components/Navbar';
import { useAuthGuard } from '@/app/hooks/useAuthGuard';
import SecureVideoPlayer from '@/components/SecureVideoPlayer';
import api from '@/lib/axios'; // 🚀 الاعتماد الكلي على Axios
import {
  ArrowRightIcon, ArrowLeftIcon, BookIcon, FileTextIcon,
  ShieldIcon, CheckIcon, AlertTriangleIcon, LockIcon,
  MonitorIcon, UploadIcon, DownloadIcon, CheckCircleIcon
} from '@/app/components/Icons';

interface Lecture {
  id: number;
  title: string;
  description: string;
  courseId: number;
}

interface PlaybackData {
  url: string;
  watermark: string;
}

interface CourseLecture {
  id: number;
  title: string;
  isCompleted: boolean;
  hasExam: boolean;
}

export default function LecturePage() {
  const { isChecking } = useAuthGuard();
  const router = useRouter();
  const params = useParams();
  const lectureId = params.id as string;

  const [lecture, setLecture] = useState<Lecture | null>(null);
  const [playback, setPlayback] = useState<PlaybackData | null>(null);
  const [courseLectures, setCourseLectures] = useState<CourseLecture[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const [violationCount, setViolationCount] = useState(0);
  const [token, setToken] = useState<string>('');

  const [streamId] = useState(() => Math.random().toString(36).substring(2, 15) + Date.now().toString(36));

  const [initialTime, setInitialTime] = useState<number>(0);
  const [isLectureCompleted, setIsLectureCompleted] = useState<boolean>(false);
  const [viewsCount, setViewsCount] = useState<number>(0);
  const [maxViews, setMaxViews] = useState<number | null>(null);

  const [homeworkData, setHomeworkData] = useState<any>(null);
  const [submittingHomework, setSubmittingHomework] = useState(false);
  const [homeworkError, setHomeworkError] = useState('');

  const lastSyncTimeRef = useRef<number>(0);
  const latestProgressRef = useRef<{time: number, duration: number} | null>(null);

  // تحديث التقدم عند مغادرة الصفحة
  useEffect(() => {
    return () => {
      if (latestProgressRef.current) {
        const { time, duration } = latestProgressRef.current;
        api.post(`/lectures/${lectureId}/progress`, { 
          watch_time: time, 
          total_duration: duration, 
          stream_id: streamId 
        }).catch(() => {});
      }
    };
  }, [lectureId, streamId]);

  useEffect(() => {
    // 🚀 استخراج التوكن لتمريره إلى مشغل الفيديو الذي يعتمد على XHR داخلي
    const currentToken = document.cookie.split('; ').find(row => row.startsWith('token='))?.split('=')[1] || localStorage.getItem('token');

    if (!currentToken) {
      router.push('/login');
      return;
    }
    setToken(currentToken);

    const loadData = async () => {
      try {
        // 🚀 كل الاستدعاءات أصبحت بـ Axios بدون إضافة /api وبدون Header يدوي
        const courseId = await fetchLectureDetails();
        const promises = [
          fetchViolationCount(),
          fetchProgress(),
          fetchLecturePlayback(),
          fetchHomeworkStatus()
        ];

        if (courseId) {
          promises.push(fetchCourseLectures(courseId));
        }

        await Promise.all(promises);
      } catch (e) {
        console.error('Error loading data:', e);
      } finally {
        setLoading(false);
      }
    };

    if (!isChecking) loadData();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [lectureId, isChecking]);

  const fetchProgress = async () => {
    try {
      const response = await api.get(`/lectures/${lectureId}/progress`);
      const data = response.data?.data || response.data;
      setInitialTime(data?.watchTime ?? data?.watch_time ?? 0);
      setIsLectureCompleted(data?.isCompleted ?? data?.is_completed ?? false);
      setViewsCount(data?.viewsCount ?? data?.views_count ?? 0);
      setMaxViews(data?.maxViews ?? data?.max_views ?? null);
    } catch (error) {}
  };

  const fetchLecturePlayback = async () => {
    try {
      const response = await api.get(`/video/playback/${lectureId}`);
      const data = response.data;
      setPlayback({
        url: data.data?.playbackUrl || data.playbackUrl || data.playback_url,
        watermark: data.data?.watermark || data.watermark
      });
    } catch (error: any) {
      if (error.response?.status === 401) router.replace('/login');
      else setError(error.response?.data?.message || error.response?.data?.error || 'الفيديو غير متاح أو قيد المعالجة.');
    }
  };

  const fetchLectureDetails = async () => {
     try {
      const response = await api.get(`/lectures/${lectureId}`);
      const data = response.data?.data || response.data;
      const extractedCourseId = data.courseId || data.course_id || data.course?.id;
      setLecture({
        id: data.id,
        title: data.title,
        description: data.description,
        courseId: extractedCourseId,
      });
      return extractedCourseId;
    } catch (error) {}
    return null;
  };

  const fetchViolationCount = async () => {
    try {
      const response = await api.get(`/violations/count`);
      const data = response.data?.data || response.data;
      setViolationCount(data?.fatalStrikes ?? data?.fatal_strikes ?? 0);
    } catch (error) {}
  };

  const fetchCourseLectures = async (courseId: number | string) => {
    try {
      const response = await api.get(`/courses/${courseId}`);
      const data = response.data?.data || response.data;
      const list = Array.isArray(data.lectures) ? data.lectures : [];
      setCourseLectures(list.map((l: any) => ({
        id: l.id,
        title: l.title,
        isCompleted: l.isCompleted ?? l.is_completed ?? false,
        hasExam: l.hasExam ?? l.has_exam ?? false,
      })));
    } catch (error) {}
  };

  const fetchHomeworkStatus = async () => {
    try {
      const response = await api.get(`/lectures/${lectureId}/homework/status`);
      setHomeworkData(response.data?.data || response.data);
    } catch (error) {}
  };

  const handleHomeworkSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const fileInput = document.getElementById('homework-file') as HTMLInputElement;
    const file = fileInput?.files?.[0];
    if (!file) {
      setHomeworkError('يرجى اختيار ملف أولاً');
      return;
    }

    setSubmittingHomework(true);
    setHomeworkError('');

    try {
      const formData = new FormData();
      formData.append('file', file);

      await api.post(`/lectures/${lectureId}/homework/submit`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });

      alert('تم تسليم الواجب بنجاح!');
      fetchHomeworkStatus();
    } catch (err: any) {
      setHomeworkError(err.response?.data?.message || err.response?.data?.error || 'فشل رفع الواجب');
    } finally {
      setSubmittingHomework(false);
    }
  };

  const handleViolation = async (violationType: string) => {
    try {
      const response = await api.post(`/lectures/${lectureId}/violation`, { violation_type: violationType });
      const data = response.data?.data || response.data;
      setViolationCount(data?.fatalStrikes ?? data?.fatal_strikes ?? violationCount);
    } catch (error) {}
  };

  const saveProgressToBackend = async (currentTime: number, totalDuration: number) => {
    try {
      const response = await api.post(`/lectures/${lectureId}/progress`, { 
        watch_time: currentTime, 
        total_duration: totalDuration, 
        stream_id: streamId 
      });

      const data = response.data?.data || response.data;
      if (data?.isCompleted || data?.is_completed) {
        setIsLectureCompleted(true);
        setCourseLectures(prev => prev.map(l => l.id.toString() === lectureId ? { ...l, isCompleted: true } : l));
      }
    } catch (error) {}
  };

  const handleVideoProgress = (currentTime: number, totalDuration: number) => {
    latestProgressRef.current = { time: currentTime, duration: totalDuration };
    const now = Date.now();
    if (now - lastSyncTimeRef.current >= 10000) {
      saveProgressToBackend(currentTime, totalDuration);
      lastSyncTimeRef.current = now;
    }
  };

  if (isChecking || loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col">
        <Navbar />
        <div className="flex-1 flex justify-center items-center">
          <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col">
        <Navbar />
        <div className="flex-1 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl p-10 max-w-md w-full text-center shadow-xl border border-gray-100">
            <div className="w-20 h-20 bg-red-50 text-red-600 rounded-full flex items-center justify-center mx-auto mb-6">
              <AlertTriangleIcon size={40} />
            </div>
            <h2 className="text-2xl font-black text-gray-900 mb-4">تنبيه</h2>
            <p className="text-gray-600 font-bold mb-8 leading-relaxed">{error}</p>
            <button onClick={() => router.back()} className="w-full bg-blue-600 text-white font-bold py-4 rounded-xl hover:bg-blue-700 transition-colors">
              العودة للخلف
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (!playback) return null;

  const completedLecturesCount = courseLectures.filter(l => l.isCompleted).length;
  const progressPercentage = courseLectures.length > 0 ? (completedLecturesCount / courseLectures.length) * 100 : 0;
  const currentIdx = courseLectures.findIndex(l => l.id.toString() === lectureId);
  const currentLectureData = currentIdx !== -1 ? courseLectures[currentIdx] : null;
  const nextLecture = currentIdx !== -1 && currentIdx < courseLectures.length - 1 ? courseLectures[currentIdx + 1] : null;

  return (
    <div className="min-h-screen bg-gray-50 font-sans pb-16">
      <Navbar />

      <div className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-8 pt-8">
        <header className="flex flex-wrap items-center justify-between gap-4 mb-8">
          <button
            onClick={() => lecture?.courseId ? router.push(`/courses/${lecture.courseId}`) : router.back()}
            className="flex items-center gap-2 text-gray-500 hover:text-blue-600 font-bold transition-colors"
          >
            <ArrowRightIcon size={20} />
            العودة لمحتويات الكورس
          </button>

          <div className="flex gap-3">
            {maxViews !== null && (
              <div className="flex items-center gap-2 bg-blue-50 text-blue-700 px-4 py-2 rounded-xl border border-blue-100 font-bold text-sm shadow-sm">
                <MonitorIcon size={16} />
                <span>مشاهداتك: {viewsCount} / {maxViews}</span>
              </div>
            )}
            {violationCount > 0 && (
              <div className={`flex items-center gap-2 px-4 py-2 rounded-xl border font-bold text-sm shadow-sm ${violationCount >= 3 ? 'bg-red-50 text-red-700 border-red-200' : 'bg-yellow-50 text-yellow-700 border-yellow-200'}`}>
                <LockIcon size={16} />
                <span>مخالفات أمنية: {violationCount}/3</span>
              </div>
            )}
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
          <div className="lg:col-span-2 flex flex-col gap-6">
            <div className="bg-black rounded-3xl overflow-hidden shadow-2xl ring-1 ring-gray-900/5">
              <SecureVideoPlayer
                lectureId={lectureId}
                videoUrl={playback.url}
                token={token}
                watermarkText={playback.watermark}
                onViolation={handleViolation}
                initialTime={initialTime}
                streamId={streamId}
                onCompleted={() => {
                  setIsLectureCompleted(true);
                  setCourseLectures(prev => prev.map(l => l.id.toString() === lectureId ? { ...l, isCompleted: true } : l));
                }}
                onProgress={handleVideoProgress}
              />
            </div>

            <div className="bg-white rounded-3xl p-6 md:p-8 border border-gray-100 shadow-sm flex flex-col md:flex-row gap-6 justify-between items-center">
              <div className="flex-1 w-full text-center md:text-right">
                <h1 className="text-2xl md:text-3xl font-black text-gray-900 mb-3 flex items-center justify-center md:justify-start gap-3">
                  <BookIcon size={32} className="text-blue-600" />
                  {lecture?.title || 'جاري التحميل...'}
                </h1>
                {lecture?.description && (
                  <p className="text-gray-500 font-medium leading-relaxed max-w-2xl">
                    {lecture.description}
                  </p>
                )}
              </div>

              <div className="flex flex-col gap-3 w-full md:w-auto shrink-0">
                {currentLectureData?.hasExam && (
                  <button onClick={() => router.push(`/exams/${lectureId}`)} className="w-full md:w-auto flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-3.5 rounded-xl font-bold transition-all shadow-lg shadow-indigo-200">
                    <FileTextIcon size={20} />
                    اختبار المحاضرة
                  </button>
                )}
                {nextLecture && (
                  <button onClick={() => router.push(`/lectures/${nextLecture.id}`)} className="w-full md:w-auto flex items-center justify-center gap-2 bg-blue-50 hover:bg-blue-600 text-blue-700 hover:text-white border border-blue-100 hover:border-blue-600 px-8 py-3.5 rounded-xl font-bold transition-all">
                    <ArrowLeftIcon size={20} />
                    المحاضرة التالية
                  </button>
                )}
              </div>
            </div>

            <div className="bg-blue-50 border border-blue-200 rounded-2xl p-5 flex items-start md:items-center gap-4 shadow-sm">
              <div className="text-blue-600 shrink-0 bg-white p-2 rounded-full shadow-sm"><ShieldIcon size={24} /></div>
              <p className="text-sm md:text-base text-blue-900 font-medium leading-relaxed">
                <strong className="font-black block md:inline mb-1 md:mb-0 ml-1">سياسة الحماية الصارمة:</strong> 
                هذا المحتوى محمي بأنظمة تتبع رقمية. محاولة استخدام أدوات المطور، أو إضافات التحميل، أو مشاركة الحساب ستؤدي للحظر النهائي مباشرة.
              </p>
            </div>

            {homeworkData && homeworkData.homework && (
              <div className="bg-white rounded-3xl p-6 md:p-8 border border-gray-100 shadow-sm mt-4 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-2 h-full bg-indigo-500"></div>

                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 pb-6 border-b border-gray-100 mb-6">
                  <h3 className="text-xl font-black text-gray-900 flex items-center gap-2">
                    <BookIcon size={24} className="text-indigo-500" />
                    الواجب الدراسي: {homeworkData.homework.title}
                  </h3>
                  <a href={homeworkData.homework.filePath} target="_blank" rel="noreferrer" className="flex items-center gap-2 bg-gray-50 hover:bg-gray-100 text-gray-700 border border-gray-200 px-5 py-2.5 rounded-xl font-bold transition-colors text-sm">
                    <DownloadIcon size={18} />
                    تحميل ملف الأسئلة
                  </a>
                </div>

                {homeworkData.submission ? (
                  <div className="flex flex-col gap-5">
                    <div className="flex items-center gap-3">
                      <span className="font-bold text-gray-700">حالة الواجب:</span>
                      {homeworkData.submission.status === 'approved' && (
                        <span className="bg-green-100 text-green-700 px-4 py-1.5 rounded-lg text-sm font-bold flex items-center gap-1.5">
                          <CheckCircleIcon size={16} /> مقبول {homeworkData.submission.score !== null && `(${homeworkData.submission.score}%)`}
                        </span>
                      )}
                      {homeworkData.submission.status === 'pending' && (
                        <span className="bg-yellow-100 text-yellow-700 px-4 py-1.5 rounded-lg text-sm font-bold">قيد المراجعة</span>
                      )}
                      {homeworkData.submission.status === 'rejected' && (
                        <span className="bg-red-100 text-red-700 px-4 py-1.5 rounded-lg text-sm font-bold">مرفوض</span>
                      )}
                    </div>

                    {homeworkData.submission.status === 'rejected' && homeworkData.submission.rejectionReason && (
                      <div className="bg-red-50 text-red-800 p-4 rounded-xl border border-red-100 text-sm font-bold">
                        <span className="text-red-600 block mb-1">سبب الرفض:</span>
                        {homeworkData.submission.rejectionReason}
                      </div>
                    )}

                    {homeworkData.submission.status === 'rejected' && (
                      <form onSubmit={handleHomeworkSubmit} className="mt-2 bg-gray-50 p-5 rounded-2xl border border-gray-100">
                        <label className="block font-bold text-gray-700 mb-3">أعد إرسال الحل بعد التصحيح:</label>
                        <div className="flex flex-col sm:flex-row gap-3 items-center">
                          <input type="file" id="homework-file" accept="image/*,application/pdf" className="w-full bg-white border border-gray-300 rounded-xl px-4 py-2.5 focus:ring-2 focus:ring-indigo-500 focus:outline-none" required />
                          <button type="submit" disabled={submittingHomework} className="w-full sm:w-auto shrink-0 flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-3 rounded-xl font-bold transition-all disabled:opacity-70">
                            <UploadIcon size={18} />
                            {submittingHomework ? 'جاري الرفع...' : 'إعادة التسليم'}
                          </button>
                        </div>
                        {homeworkError && <p className="text-red-500 text-sm font-bold mt-2">{homeworkError}</p>}
                      </form>
                    )}
                  </div>
                ) : (
                  <form onSubmit={handleHomeworkSubmit} className="bg-gray-50 p-6 rounded-2xl border border-gray-100">
                    <label className="block font-bold text-gray-900 mb-4">أرفق ملف إجابتك (صورة واضحة أو PDF):</label>
                    <div className="flex flex-col sm:flex-row gap-3 items-center">
                      <input type="file" id="homework-file" accept="image/*,application/pdf" className="w-full bg-white border border-gray-300 rounded-xl px-4 py-3 focus:ring-2 focus:ring-indigo-500 focus:outline-none" required />
                      <button type="submit" disabled={submittingHomework} className="w-full sm:w-auto shrink-0 flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-3 rounded-xl font-bold transition-all disabled:opacity-70 shadow-lg shadow-indigo-200">
                        <UploadIcon size={20} />
                        {submittingHomework ? 'جاري الرفع...' : 'تسليم الواجب'}
                      </button>
                    </div>
                    {homeworkError && <p className="text-red-500 text-sm font-bold mt-3">{homeworkError}</p>}
                  </form>
                )}
              </div>
            )}
          </div>

          <aside className="lg:col-span-1">
            <div className="bg-white rounded-3xl border border-gray-100 shadow-sm sticky top-6">
              <div className="p-6 border-b border-gray-100 bg-gray-50 rounded-t-3xl">
                <h3 className="text-lg font-black text-gray-900 flex items-center gap-2 mb-4">
                  <FileTextIcon size={22} className="text-blue-600" />
                  محتويات المنهج
                </h3>

                <div className="bg-white p-4 rounded-2xl border border-gray-200 shadow-sm">
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-sm font-bold text-gray-500">نسبة الإنجاز</span>
                    <span className="text-sm font-black text-green-600">{Math.round(progressPercentage)}%</span>
                  </div>
                  <div className="w-full h-2.5 bg-gray-100 rounded-full overflow-hidden">
                    <div className="h-full bg-green-500 rounded-full transition-all duration-500 ease-out" style={{ width: `${progressPercentage}%` }}></div>
                  </div>
                </div>
              </div>

              <div className="p-4 flex flex-col gap-2 max-h-[60vh] overflow-y-auto overflow-x-hidden custom-scrollbar">
                {courseLectures.length > 0 ? (
                  courseLectures.map((lec, index) => {
                    const isCurrent = lec.id.toString() === lectureId;
                    const isCompleted = lec.isCompleted;

                    return (
                      <button
                        key={lec.id}
                        onClick={() => { if (!isCurrent) router.push(`/lectures/${lec.id}`); }}
                        className={`flex items-center gap-4 w-full p-3.5 rounded-2xl transition-all border text-right
                          ${isCurrent ? 'bg-blue-600 border-blue-600 text-white shadow-md transform scale-[1.02]' : 
                            isCompleted ? 'bg-green-50 border-green-100 text-gray-700 hover:bg-green-100' : 
                            'bg-white border-transparent text-gray-600 hover:bg-gray-50 hover:border-gray-200'}
                        `}
                      >
                        <div className={`w-10 h-10 shrink-0 rounded-xl flex items-center justify-center font-black text-sm
                          ${isCurrent ? 'bg-white/20 text-white' : 
                            isCompleted ? 'bg-green-100 text-green-600' : 
                            'bg-gray-100 text-gray-400'}
                        `}>
                          {isCompleted && !isCurrent ? <CheckIcon size={16} /> : index + 1}
                        </div>

                        <div className="flex-1 min-w-0">
                          <p className={`text-sm truncate ${isCurrent || isCompleted ? 'font-black' : 'font-bold'}`}>
                            {lec.title}
                          </p>
                        </div>
                      </button>
                    );
                  })
                ) : (
                  <p className="text-gray-400 text-center font-bold py-8">جاري تحميل المحاضرات...</p>
                )}
              </div>
            </div>
          </aside>
        </div>
      </div>

      <style jsx global>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
