'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import Navbar from '../components/Navbar';
import {
  ArrowRightIcon, ArrowLeftIcon, KeyIcon, CodeIcon,
  CheckCircleIcon, GraduationCapIcon, PlayCircleIcon,
  AlertTriangleIcon, FileTextIcon, BookIcon, LockIcon
} from '../components/Icons';

const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";

const getToken = () => {
  return document.cookie.split('; ').find(row => row.startsWith('token='))?.split('=')[1] || localStorage.getItem('token');
};

interface SuccessData {
  message: string;
  course: {
    id: number;
    title: string;
  };
}

export default function RedeemCodePage() {
  const router = useRouter();
  const [code, setCode] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState<SuccessData | null>(null);

  useEffect(() => {
    const checkAuth = async () => {
      const token = getToken();
      if (!token) {
        router.push('/login');
        return;
      }

      const statusRes = await fetch(`${API_URL}/api/auth/status`, {
        headers: { Authorization: `Bearer ${token}`, Accept: 'application/json' },
      });
      if (statusRes.ok) {
        const statusData = await statusRes.json();
        if (statusData.data?.status === 'pending') {
          router.replace('/waiting-room');
        }
      }
    };
    checkAuth();
  }, [router]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess(null);
    setLoading(true);

    try {
      const token = getToken();

      if (!token) {
        router.push('/login');
        return;
      }

      const response = await fetch(`${API_URL}/api/student/center-codes/redeem`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({ code: code.trim().toUpperCase() }),
      });

      const data = await response.json();

      if (response.ok) {
        setSuccess({
          message: data.data?.message || data.message || 'تم تفعيل الكورس بنجاح',
          course: data.data?.course || data.course
        });
        setCode('');
      } else {
        setError(data.error || data.message || 'الكود غير صحيح أو مستخدم مسبقاً');
      }
    } catch (err) {
      console.error('Redemption failed:', err);
      setError('حدث خطأ أثناء الاتصال بالخادم. يرجى المحاولة لاحقاً.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="page-container">
      <Navbar />

      <div style={{
        position: 'fixed',
        inset: 0,
        pointerEvents: 'none',
        zIndex: -1,
        overflow: 'hidden'
      }}>
        <div style={{
          position: 'absolute',
          width: 350,
          height: 350,
          borderRadius: '60% 40% 30% 70% / 60% 30% 70% 40%',
          background: 'linear-gradient(135deg, rgba(11, 79, 108, 0.12) 0%, rgba(27, 189, 212, 0.12) 100%)',
          top: -80,
          insetInlineEnd: -80,
          animation: 'blob 8s ease-in-out infinite',
        }} />
        <div style={{
          position: 'absolute',
          width: 250,
          height: 250,
          borderRadius: '30% 60% 70% 40% / 50% 60% 30% 60%',
          background: 'linear-gradient(135deg, rgba(59, 130, 246, 0.1) 0%, rgba(16, 185, 129, 0.1) 100%)',
          bottom: '20%',
          insetInlineStart: -50,
          animation: 'blob 10s ease-in-out infinite',
          animationDelay: '-2s',
        }} />
      </div>

      <div className="page-content" style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        minHeight: 'calc(100vh - 80px)'
      }}>
        <div style={{ width: '100%', maxWidth: '480px' }}>
          <Link href="/dashboard" style={{
            display: 'inline-flex',
            alignItems: 'center',
            gap: '0.5rem',
            color: 'var(--primary)',
            textDecoration: 'none',
            fontWeight: 600,
            marginBottom: '1.5rem',
            transition: 'all 0.3s'
          }}>
            <ArrowRightIcon size={16} />
            العودة للوحة التحكم
          </Link>

          <div className="card" style={{
            textAlign: 'center',
            background: 'var(--surface)',
            border: '2px solid var(--border)',
            borderRadius: 'var(--radius-xl)',
            padding: '2.5rem 2rem',
            boxShadow: 'var(--shadow-lg)'
          }}>
            <div style={{
              width: 90,
              height: 90,
              borderRadius: 'var(--radius-lg)',
              background: 'var(--gradient-primary)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              margin: '0 auto 1.5rem',
              boxShadow: 'var(--shadow-lg)',
            }}>
              <KeyIcon size={36} style={{ color: 'white' }} />
            </div>

            <h1 style={{
              fontFamily: 'var(--font-display)',
              fontSize: '1.75rem',
              fontWeight: 800,
              color: 'var(--text-primary)',
              marginBottom: '0.5rem'
            }}>
              <CodeIcon size={24} style={{ marginInlineEnd: '0.5rem', verticalAlign: 'middle' }} />
              استخدام كود المركز
            </h1>

            <p style={{
              color: 'var(--text-secondary)',
              marginBottom: '2rem',
              lineHeight: 1.7
            }}>
              أدخل الكود الذي حصلت عليه من المركز للحصول على الكورس المميز
            </p>

            {success && (
              <div className="banner banner-success" style={{ marginBottom: '1.5rem', textAlign: 'center', display: 'block' }}>
                <CheckCircleIcon size={24} style={{ marginBottom: '0.5rem' }} />
                <p style={{
                  fontWeight: 700,
                  color: 'var(--success-dark)',
                  fontSize: '1.1rem',
                  marginBottom: '0.5rem'
                }}>
                  {success.message}
                </p>
                <p style={{ color: 'var(--text-secondary)', marginBottom: '1rem' }}>
                  <GraduationCapIcon size={16} style={{ marginInlineEnd: '0.25rem', verticalAlign: 'middle' }} />
                  الكورس: <strong>{success.course.title}</strong>
                </p>
                <Link
                  href={`/courses/${success.course.id}`}
                  className="btn btn-primary"
                  style={{ textDecoration: 'none', width: '100%', display: 'inline-flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }}
                >
                  بدء الكورس
                  <ArrowLeftIcon size={16} />
                </Link>
              </div>
            )}

            {error && (
              <div className="banner banner-error" style={{ marginBottom: '1.5rem' }}>
                <AlertTriangleIcon size={16} />
                {error}
              </div>
            )}

            {!success && (
              <form onSubmit={handleSubmit}>
                <div className="form-group" style={{ marginBottom: '1.5rem' }}>
                  <label className="form-label" style={{ textAlign: 'right', fontWeight: 700 }}>
                    <CodeIcon size={16} style={{ marginInlineEnd: '0.25rem', verticalAlign: 'middle' }} />
                    أدخل الكود هنا
                  </label>
                  <input
                    type="text"
                    value={code}
                    onChange={(e) => setCode(e.target.value.toUpperCase())}
                    placeholder="XXXX-XXXX-XXXX"
                    required
                    className="input-field"
                    style={{
                      textAlign: 'center',
                      fontFamily: 'monospace',
                      fontSize: '1.25rem',
                      letterSpacing: '0.15em',
                      fontWeight: 700,
                      padding: '1rem'
                    }}
                  />
                  <p style={{
                    fontSize: '0.75rem',
                    color: 'var(--text-muted)',
                    marginTop: '0.5rem'
                  }}>
                    <FileTextIcon size={12} style={{ marginInlineEnd: '0.25rem', verticalAlign: 'middle' }} />
                    الكود يتكون من 12 حرف وأرقام مفصولة بشرطات
                  </p>
                </div>

                <button
                  type="submit"
                  disabled={loading || !code.trim()}
                  className="btn btn-primary btn-block"
                  style={{
                    padding: '1rem',
                    fontSize: '1.1rem'
                  }}
                >
                  {loading ? (
                    <>
                      <div className="spinner" style={{ width: 18, height: 18, marginInlineEnd: '8px' }}></div>
                      جاري التحقق والتفعيل...
                    </>
                  ) : (
                    'تفعيل الكود الآن'
                  )}
                </button>
              </form>
            )}

            {!success && (
              <div style={{
                marginTop: '2rem',
                paddingTop: '1.5rem',
                borderTop: '1px solid var(--border)'
              }}>
                <p style={{
                  fontSize: '0.875rem',
                  color: 'var(--text-muted)',
                  marginBottom: '0.75rem'
                }}>
                  ليس لديك كود؟ وتريد الشراء أونلاين؟
                </p>
                <Link href="/courses" style={{
                  color: 'var(--primary)',
                  textDecoration: 'none',
                  fontWeight: 700,
                  fontSize: '0.9375rem',
                  display: 'inline-flex',
                  alignItems: 'center',
                  gap: '0.5rem'
                }}>
                  <BookIcon size={16} />
                  تصفح الكورسات المتاحة
                </Link>
              </div>
            )}
          </div>

          <div style={{ textAlign: 'center', marginTop: '1.5rem', opacity: 0.6 }}>
            <LockIcon size={20} style={{ margin: '0 0.25rem', verticalAlign: 'middle', display: 'inline-block' }} />
            <span style={{ fontSize: '0.875rem', color: 'var(--text-muted)', fontWeight: 'bold' }}>
              عملية التفعيل آمنة ومشفرة تماماً
            </span>
          </div>
        </div>
      </div>

      <style jsx>{`
        @keyframes blob {
          0%, 100% { border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%; }
          50% { border-radius: 30% 60% 70% 40% / 50% 60% 30% 60%; }
        }
      `}</style>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import Cookies from 'js-cookie';
import Navbar from '../components/Navbar';
import api from '@/lib/axios'; // 🚀 عميل الشبكة المركزي
import { useAuthStore } from '@/store/useAuthStore'; // 🚀 محرك الحالة
import {
  BookIcon,
  UserIcon,
  ImageIcon,
  CheckIcon,
  ArrowLeftIcon,
  ArrowRightIcon,
  AlertCircleIcon,
} from '../components/Icons';

interface FormData {
  full_name: string;
  academic_year: string;
  student_number: string;
  phone: string;
  parent_phone: string;
  school: string;
  parent_job: string;
  governorate: string;
  email: string;
  password: string;
  confirmPassword: string;
  id_image: File | null;
}

interface FormErrors {
  [key: string]: string | undefined;
}

const academicYears = ['الاول الابتدائي', 'الثاني الابتدائي', 'الثالث الابتدائي', 'الرابع الابتدائي', 'الخامس الابتدائي', 'السادس الابتدائي', 'الاول الاعدادي', 'الثاني الاعدادي', 'الثالث الاعدادي', 'الاول الثانوي', 'الثاني الثانوية', 'الثالث الثانوي'];

const governorates = [
  'القاهرة', 'الجيزة', 'الاسكندرية', 'الدقهلية', 'البحيرة', 'الغربية', 'المنوفية', 'الشرقية', 'القليوبية',
  'كفر الشيخ', 'الاقصر', 'اسوان', 'سوهاج', 'المنيا', 'قنا', 'الوادي الجديد', 'البحر الاحمر', 'السويس',
  'الاسماعيلية', 'بورسعيد', 'دمياط', 'شمال سيناء', 'جنوب سيناء'
];

export default function RegisterPage() {
  const router = useRouter();
  const { isAuthenticated } = useAuthStore();

  // 🚀 التوجيه الذكي: منع المسجلين من رؤية صفحة التسجيل
  useEffect(() => {
    if (isAuthenticated || Cookies.get('token')) {
      router.replace('/dashboard');
    }
  }, [isAuthenticated, router]);

  const [step, setStep] = useState(1);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [toast, setToast] = useState<{ visible: boolean; message: string; type: 'success' | 'error' }>({ visible: false, message: '', type: 'success' });

  const showToast = (message: string, type: 'success' | 'error') => {
    setToast({ visible: true, message, type });
    setTimeout(() => setToast({ visible: false, message: '', type: 'success' }), 4000);
  };

  const [formData, setFormData] = useState<FormData>({
    full_name: '',
    academic_year: '',
    student_number: '',
    phone: '',
    parent_phone: '',
    school: '',
    parent_job: '',
    governorate: '',
    email: '',
    password: '',
    confirmPassword: '',
    id_image: null,
  });

  const [errors, setErrors] = useState<FormErrors>({});
  const [imagePreview, setImagePreview] = useState<string | null>(null);

  const validateStep1 = (): boolean => {
    const newErrors: FormErrors = {};

    if (!formData.full_name.trim()) newErrors.full_name = 'الاسم الكامل مطلوب';
    if (!formData.email.trim()) {
      newErrors.email = 'البريد الإلكتروني مطلوب';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      newErrors.email = 'البريد الإلكتروني غير صالح';
    }

    if (!formData.password) {
      newErrors.password = 'كلمة المرور مطلوبة';
    } else if (formData.password.length < 8) {
      newErrors.password = 'يجب أن تكون كلمة المرور 8 أحرف على الأقل';
    }

    if (!formData.confirmPassword) {
      newErrors.confirmPassword = 'تأكيد كلمة المرور مطلوب';
    } else if (formData.password !== formData.confirmPassword) {
      newErrors.confirmPassword = 'كلمات المرور غير متطابقة';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const validateStep2 = (): boolean => {
    const newErrors: FormErrors = {};

    if (!formData.academic_year) newErrors.academic_year = 'السنة الدراسية مطلوبة';
    if (!formData.student_number.trim()) newErrors.student_number = 'رقم الطالب مطلوب';

    if (!formData.phone.trim()) {
      newErrors.phone = 'رقم الهاتف مطلوب';
    } else if (!/^01[0125][0-9]{8}$/.test(formData.phone.replace(/\s/g, ''))) {
      newErrors.phone = 'رقم الهاتف غير صالح';
    }

    if (!formData.parent_phone.trim()) {
      newErrors.parent_phone = 'هاتف ولي الأمر مطلوب';
    } else if (!/^01[0125][0-9]{8}$/.test(formData.parent_phone.replace(/\s/g, ''))) {
      newErrors.parent_phone = 'رقم الهاتف غير صالح';
    }

    if (!formData.school.trim()) newErrors.school = 'اسم المدرسة مطلوب';
    if (!formData.parent_job.trim()) newErrors.parent_job = 'وظيفة ولي الأمر مطلوبة';
    if (!formData.governorate) newErrors.governorate = 'المحافظة مطلوبة';
    if (!formData.id_image) newErrors.id_image = 'صورة البطاقة مطلوبة';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleChange = (field: keyof FormData, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors(prev => ({ ...prev, [field]: undefined }));
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setErrors(prev => ({ ...prev, id_image: 'يجب أن يكون الملف صورة' }));
        return;
      }
      if (file.size > 5 * 1024 * 1024) {
        setErrors(prev => ({ ...prev, id_image: 'حجم الملف يجب أن يكون أقل من 5 ميجابايت' }));
        return;
      }
      setFormData(prev => ({ ...prev, id_image: file }));

      if (imagePreview) URL.revokeObjectURL(imagePreview);
      setImagePreview(URL.createObjectURL(file));
      setErrors(prev => ({ ...prev, id_image: undefined }));
    }
  };

  const handleNext = () => {
    if (validateStep1()) setStep(2);
  };

  const handleBack = () => {
    setStep(1);
  };

  const handleSubmit = async () => {
    if (!validateStep2()) return;

    setIsLoading(true);
    setError('');

    try {
      const formDataToSend = new FormData();
      formDataToSend.append('full_name', formData.full_name);
      formDataToSend.append('academic_year', formData.academic_year);
      formDataToSend.append('student_number', formData.student_number);
      formDataToSend.append('phone', formData.phone.replace(/\s/g, ''));
      formDataToSend.append('parent_phone', formData.parent_phone.replace(/\s/g, ''));
      formDataToSend.append('school', formData.school);
      formDataToSend.append('parent_job', formData.parent_job);
      formDataToSend.append('governorate', formData.governorate);
      formDataToSend.append('email', formData.email);
      formDataToSend.append('password', formData.password);
      formDataToSend.append('password_confirmation', formData.confirmPassword);

      if (formData.id_image) {
        formDataToSend.append('id_image', formData.id_image);
      }

      const response: any = await api.post('/auth/register', formDataToSend, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });

      // 🚀 استخراج ذكي جداً يبحث في كل الطبقات المحتملة للاستجابة
      const tempId = response?.data?.data?.tempUserId || response?.data?.tempUserId || response?.tempUserId || response?.data?.temp_user_id;

      if (tempId) {
        // 1. تخزين الرقم لاستخدامه في صفحة الـ OTP لإرسال الرسالة
        sessionStorage.setItem('pending_phone', `+2${formData.phone}`);

        showToast("تم التسجيل مبدئياً بنجاح، جاري التوجيه للتحقق...", "success");

        // توجيه الطالب بعد 1.5 ثانية لكي يرى رسالة النجاح
        setTimeout(() => {
            router.push(`/otp?tempUserId=${tempId}`);
        }, 1500);
      } else {
        // 🚀 إضافة هذا الشرط لمنع الفشل الصامت مجدداً
        console.error("استجابة السيرفر:", response);
        setError("تم إنشاء الحساب لكن السيرفر لم يُرجع كود التحقق. يرجى تسجيل الدخول.");
      }

    } catch (err: any) {
      if (err.errors) {
        const serverErrors: FormErrors = {};
        Object.keys(err.errors).forEach(key => {
          serverErrors[key] = err.errors[key][0];
        });

        setErrors(serverErrors);
        setError('يرجى مراجعة الحقول باللون الأحمر وتصحيحها');

        if (serverErrors.full_name || serverErrors.email || serverErrors.password) {
          setStep(1);
        }
      } else {
        setError(err.message || 'حدث خطأ غير متوقع أثناء التسجيل');
      }
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <>
      <Navbar />

      {error && (
        <div className="toast-container show">
          <div className="toast-content error" style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <AlertCircleIcon size={18} />
            <span>{error}</span>
          </div>
        </div>
      )}

      {toast.visible && (
        <div className="toast-container show">
          <div className={`toast-content ${toast.type}`} style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <CheckIcon size={18} />
            <span>{toast.message}</span>
          </div>
        </div>
      )}

      <div className="split-layout">
        <div className="split-branding">
          <div className="branding-content text-center">
            <BookIcon size={64} color="white" />
            <h1 className="branding-title" style={{ fontSize: '3rem', fontWeight: 900, marginBottom: '1rem' }}>منصتنا</h1>
            <p className="branding-subtitle" style={{ fontSize: '1.25rem', opacity: 0.9, maxWidth: '400px', margin: '0 auto' }}>منصتك التعليمية الذكية لتطوير مهاراتك والتفوق في دراستك</p>
          </div>
        </div>

        <div className="split-form">
          <div className="split-card">
            <div className="split-card-header">
              <div className="icon-circle">
                <UserIcon size={28} />
              </div>
              <h2 className="split-card-title">إنشاء حساب جديد</h2>
              <p className="split-card-subtitle">املأ البيانات التالية للتسجيل في منصتنا</p>
            </div>

            <div className="step-indicator">
              <div className={`step-dot ${step >= 1 ? (step > 1 ? 'completed' : 'active') : ''}`}>
                {step > 1 ? <CheckIcon size={16} /> : '1'}
              </div>
              <div className={`step-line ${step > 1 ? 'completed' : ''}`} />
              <div className={`step-dot ${step === 2 ? 'active' : ''}`}>
                2
              </div>
            </div>

            {step === 1 && (
              <div className="split-card-form">
                <div className="form-group">
                  <label htmlFor="full_name" className="form-label">الاسم الكامل (رباعي)</label>
                  <input
                    id="full_name"
                    type="text"
                    className={`input-field ${errors.full_name ? 'error' : ''}`}
                    placeholder="أدخل الاسم الكامل"
                    value={formData.full_name}
                    onChange={(e) => handleChange('full_name', e.target.value)}
                  />
                  {errors.full_name && <p className="form-error">{errors.full_name}</p>}
                </div>

                <div className="form-group">
                  <label htmlFor="email" className="form-label">البريد الإلكتروني</label>
                  <input
                    id="email"
                    type="email"
                    className={`input-field ${errors.email ? 'error' : ''}`}
                    placeholder="example@email.com"
                    value={formData.email}
                    onChange={(e) => handleChange('email', e.target.value)}
                    dir="ltr"
                  />
                  {errors.email && <p className="form-error">{errors.email}</p>}
                </div>

                <div className="form-group">
                  <label htmlFor="password" className="form-label">كلمة المرور</label>
                  <input
                    id="password"
                    type="password"
                    className={`input-field ${errors.password ? 'error' : ''}`}
                    placeholder="••••••••"
                    value={formData.password}
                    onChange={(e) => handleChange('password', e.target.value)}
                    dir="ltr"
                  />
                  {errors.password && <p className="form-error">{errors.password}</p>}
                  <p className="text-muted" style={{ fontSize: '0.75rem', marginTop: '0.25rem' }}>يجب أن تكون 8 أحرف على الأقل مع أرقام وحروف</p>
                </div>

                <div className="form-group">
                  <label htmlFor="confirmPassword" className="form-label">تأكيد كلمة المرور</label>
                  <input
                    id="confirmPassword"
                    type="password"
                    className={`input-field ${errors.confirmPassword ? 'error' : ''}`}
                    placeholder="••••••••"
                    value={formData.confirmPassword}
                    onChange={(e) => handleChange('confirmPassword', e.target.value)}
                    dir="ltr"
                  />
                  {errors.confirmPassword && <p className="form-error">{errors.confirmPassword}</p>}
                </div>

                <button type="button" className="btn btn-primary btn-block" onClick={handleNext}>
                  التالي
                  <ArrowLeftIcon size={18} />
                </button>
              </div>
            )}

            {step === 2 && (
              <div className="split-card-form">
                <div className="grid grid-cols-2 gap-4">
                  <div className="form-group">
                    <label htmlFor="academic_year" className="form-label">السنة الدراسية</label>
                    <select
                      id="academic_year"
                      className={`input-field ${errors.academic_year ? 'error' : ''}`}
                      value={formData.academic_year}
                      onChange={(e) => handleChange('academic_year', e.target.value)}
                    >
                      <option value="">اختر...</option>
                      {academicYears.map(year => (
                        <option key={year} value={year}>{year}</option>
                      ))}
                    </select>
                    {errors.academic_year && <p className="form-error">{errors.academic_year}</p>}
                  </div>

                  <div className="form-group">
                    <label htmlFor="student_number" className="form-label">رقم الطالب السري</label>
                    <input
                      id="student_number"
                      type="text"
                      className={`input-field ${errors.student_number ? 'error' : ''}`}
                      placeholder="رقم الطالب"
                      value={formData.student_number}
                      onChange={(e) => handleChange('student_number', e.target.value)}
                      dir="ltr"
                    />
                    {errors.student_number && <p className="form-error">{errors.student_number}</p>}
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="form-group">
