                        <th>الطريقة</th>
                        <th>حالة الطلب</th>
                        <th>التاريخ</th>
                      </tr>
                    </thead>
                    <tbody>
                      {topupHistory.map(req => (
                        <tr key={req.id}>
                          <td>
                            <span className="font-bold" dir="ltr">
