// lib/axios.ts

import axios, { AxiosError, InternalAxiosRequestConfig, AxiosResponse } from 'axios';
import Cookies from 'js-cookie';
import { ApiResponse, ApiError } from '@/types/api';

// 🚀 1. إعداد النسخة الأساسية
const api = axios.create({
  baseURL: process.env.NEXT_PUBLIC_API_URL || 'http://localhost:8000/api',
  headers: {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
  },
  timeout: 15000, // منع تعليق التطبيق إذا كان السيرفر بطيئاً
});

// 🚀 2. معترض الطلبات (Request Interceptor) - حقن التوكن
api.interceptors.request.use(
  (config: InternalAxiosRequestConfig) => {
    const token = Cookies.get('token');
    if (token && config.headers) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// 🚀 3. معترض الاستجابات (Response Interceptor) - الدرع الأمني وفك التغليف
api.interceptors.response.use(
  (response: AxiosResponse<ApiResponse>) => {
    // نرجع البيانات مباشرة لكي لا نضطر لكتابة response.data.data في كل صفحة
    return response.data as any; 
  },
  (error: AxiosError<ApiError>) => {
    const status = error.response?.status;

    console.error(`🚨 [Axios Error] Status: ${status} | URL: ${error.config?.url} | Message:`, error.response?.data?.message || error.message);

    const errorCode = error.response?.data?.code;

    // 🔴 401 Unauthorized: التوكن منتهي أو تم تدميره (Logout)
    if (status === 401) {
      Cookies.remove('token');
      if (typeof window !== 'undefined' && window.location.pathname !== '/login') {
        window.location.href = '/login?session_expired=true';
      }
    }

    // 🔴 403 Forbidden: الدرع الذي بنيناه في الباك إند (ActiveUserMiddleware & VideoViolation)
    if (status === 403) {
      if (errorCode === 'ERR_USER_BLOCKED') {
        Cookies.remove('token');
        if (typeof window !== 'undefined') {
          // توجيه الطالب لصفحة "تم الحظر" التي أراها في صورتك (app/blocked)
          window.location.href = '/blocked'; 
        }
      } else if (errorCode === 'ERR_USER_NOT_ACTIVE') {
        // Cookies.remove('token');
        if (typeof window !== 'undefined') {
          // توجيه لصفحة الانتظار (app/waiting-room)
          window.location.href = '/waiting-room';
        }
      }
    }

    // 🔴 409 Conflict: محاولة فتح الفيديو من جهازين
    if (status === 409 && errorCode === 'ERR_STREAM_CONFLICT') {
        // يمكنك إطلاق حدث (Event) هنا لإظهار Pop-up إجباري للمستخدم
        console.warn('Stream Conflict Detected!');
    }

    return Promise.reject(error.response?.data || error.message);
  }
);

export default api;

// services/auth.service.ts

import api from '@/lib/axios';
import Cookies from 'js-cookie';
import { ApiResponse } from '@/types/api';

// يمكنك إنشاء ملف types/models.ts لاحقاً لتحديد هيكل User
export const authService = {
  // حفظ التوكن بأمان
  setToken: (token: string) => {
    Cookies.set('token', token, { expires: 30, secure: true, sameSite: 'strict' });
  },

  // مسح التوكن
  removeToken: () => {
    Cookies.remove('token');
  },

  // جلب التوكن
  getToken: () => {
    return Cookies.get('token');
  },

  // جلب بيانات الطالب الحالي
  getMe: async () => {
    return await api.get<any, ApiResponse>('/auth/me');
  },

  // تسجيل الخروج في السيرفر
  logout: async () => {
    try {
      await api.post('/auth/logout');
    } finally {
      Cookies.remove('token');
      if (typeof window !== 'undefined') {
        window.location.href = '/login';
      }
    }
  }
};

// store/useAuthStore.ts

import { create } from 'zustand';
import { User } from '@/types/models';
import { authService } from '@/services/auth.service';
import Cookies from 'js-cookie';

interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  
  // Actions
  fetchUser: () => Promise<void>;
  logout: () => Promise<void>;
  setUser: (user: User) => void;
  updateWallet: (newBalance: number) => void;
}

export const useAuthStore = create<AuthState>((set) => ({
  user: null,
  isAuthenticated: false,
  isLoading: true, // نبدأ بـ true لكي لا نعرض شاشة تسجيل الدخول للحظة ثم ننتقل للداشبورد (FOUC)

  fetchUser: async () => {
    const token = Cookies.get('token');
    
    if (!token) {
      set({ user: null, isAuthenticated: false, isLoading: false });
      return;
    }

    try {
      const response = await authService.getMe();
      // استجابة السيرفر ستكون مغلفة بـ ApiResponse التي بنيناها
      set({ user: response.data, isAuthenticated: true, isLoading: false });
    } catch (error) {
      // إذا فشل الجلب (مثلاً التوكن منتهي أو الطالب تم حظره)، الـ Axios Interceptor سيتكفل بالباقي
      set({ user: null, isAuthenticated: false, isLoading: false });
    }
  },

  setUser: (user: User) => set({ user, isAuthenticated: true }),

  logout: async () => {
    set({ isLoading: true });
    try {
      await authService.logout();
    } catch (error) {
      console.error('Logout error', error);
    } finally {
      set({ user: null, isAuthenticated: false, isLoading: false });
    }
  },

  // ميزة للـ UX: تحديث الرصيد فوراً في الـ UI بعد الشراء بدون الحاجة لعمل Refresh
  updateWallet: (newBalance: number) => set((state) => ({
    user: state.user ? { ...state.user, walletBalance: newBalance } : null
  })),
}));

// types/api.ts

export interface PaginatedMeta {
  total: number;
  currentPage: number;
  lastPage: number;
  perPage?: number;
}

// 🚀 هذا هو الهيكل الذي برمجناه في Backend ApiResponse بالضبط
export interface ApiResponse<T = any> {
  success: boolean;
  message: string;
  data: T;
  code?: string;
  meta?: PaginatedMeta; // يظهر فقط في حالة ApiResponse::paginated()
}

// نوع موحد للأخطاء لكي نستطيع التقاطها في الـ Components
export interface ApiError {
  success: boolean;
  message: string;
  code: string;
}
